var documenterSearchIndex = {"docs":
[{"category":"section","location":"raytracing_tutorial.html#Ray-Tracing-with-Raycore","page":"Ray Tracing Tutorial","text":"book_app # hide","title":"Ray Tracing with Raycore"},{"category":"section","location":"viewfactors_content.html#View-Factors-Analysis","page":"View Factors Analysis","text":"This example demonstrates Raycore's analysis capabilities for radiosity and illumination calculations.","title":"View Factors Analysis"},{"category":"section","location":"viewfactors_content.html#Scene-Setup","page":"View Factors Analysis","text":"using Raycore, GeometryBasics, LinearAlgebra\nusing WGLMakie\nimport KernelAbstractions as KA\n\nfunction LowSphere(radius, contact=Point3f(0); ntriangles=6)\n    return Tesselation(Sphere(contact .+ Point3f(0, 0, radius), radius), ntriangles)\nend\n\n# Create scene with multiple objects (using low triangle counts to keep docs small)\nntriangles = 6\ns1 = LowSphere(0.5f0, Point3f(-0.5, 0.0, 0); ntriangles)\ns2 = LowSphere(0.3f0, Point3f(1, 0.5, 0); ntriangles)\ns3 = LowSphere(0.3f0, Point3f(-0.5, 1, 0); ntriangles)\ns4 = LowSphere(0.4f0, Point3f(0, 1.0, 0); ntriangles)\ns5 = LowSphere(0.35f0, Point3f(0.5, 0.0, 0); ntriangles)\n\n# Build meshes and TLAS with sequential triangle indices as metadata\nsphere_meshes = [normal_mesh(s) for s in [s1, s2, s3, s4, s5]]\ntlas = Raycore.TLAS(sphere_meshes, (mesh_idx, tri_idx) -> begin\n    offset = sum(length(faces(sphere_meshes[i])) for i in 1:mesh_idx-1; init=0)\n    UInt32(offset + tri_idx)\nend)\n\n# Build visualization mesh from TLAS primitives (which may have degenerate triangles removed)\n# This guarantees face count matches between the TLAS and the visualization mesh.\nfunction tlas_to_mesh(tlas)\n    verts = Point3f[]\n    norms = Vec3f[]\n    fs = GLTriangleFace[]\n    for tri in tlas.all_blas_prims\n        base = length(verts)\n        for v in tri.vertices\n            push!(verts, v)\n        end\n        for n in tri.normals\n            push!(norms, Vec3f(n))\n        end\n        push!(fs, GLTriangleFace(base + 1, base + 2, base + 3))\n    end\n    # GeometryBasics ≥ 0.5 dropped `meta(...)`; vertex normals go via the\n    # `normal` kwarg on `GeometryBasics.mesh`/`Mesh`.\n    GeometryBasics.mesh(verts, fs; normal=norms)\nend\nworld_mesh = tlas_to_mesh(tlas)\nN = length(tlas.all_blas_prims)\n\n# Visualize the scene\nf, ax, pl = mesh(world_mesh, color=:teal, axis=(show_axis=false,))\ncenter!(ax.scene)\nf","title":"Scene Setup"},{"category":"section","location":"viewfactors_content.html#View-Factors","page":"View Factors Analysis","text":"View factors quantify how much each surface \"sees\" every other surface - essential for radiosity calculations.\n\n# Calculate view factors between all faces\nviewf_matrix = view_factors(tlas, rays_per_triangle=20)\n\n# Sum up total view factor per face\nviewfacts = map(i -> Float32(sum(view(viewf_matrix, :, i))), 1:N)\n\n# Visualize\nper_face_vf = FaceView(viewfacts, [GLTriangleFace(i) for i in 1:N])\nviewfact_mesh = GeometryBasics.mesh(world_mesh, color=per_face_vf)\nmesh(viewfact_mesh, colormap=:turbo, shading=false,\n     lowclip=:black, colorrange=(0f0, maximum(viewfacts)),\n     axis=(show_axis=false,))\n\nHigher values (warm colors) indicate faces that see more of the surrounding geometry.","title":"View Factors"},{"category":"section","location":"viewfactors_content.html#Illumination","page":"View Factors Analysis","text":"Calculate how much each face is exposed to rays from a specific viewing direction.\n\n# Get camera view direction\nviewdir = normalize(ax.scene.camera.view_direction[])\n\n# Compute illumination\nillum = get_illumination(tlas, viewdir; grid_size=10)\n\n# Visualize\npf = FaceView(illum, [GLTriangleFace(i) for i in 1:N])\nillum_mesh = GeometryBasics.mesh(world_mesh, color=pf)\nmesh(illum_mesh, colormap=[:black, :yellow], colorscale=sqrt,\n     shading=false, axis=(show_axis=false,))\n\nFaces directly visible from the viewing direction show higher illumination (yellow).","title":"Illumination"},{"category":"section","location":"viewfactors_content.html#Centroid-Calculation","page":"View Factors Analysis","text":"Find the average position of visible surface points from a given direction.\n\n# Calculate centroid\nhitpoints, centroid = get_centroid(tlas, viewdir; grid_size=10)\n\n# Visualize\nf, ax, pl = mesh(world_mesh, color=(:blue, 0.5), transparency=true, axis=(show_axis=false,))\neyepos = ax.scene.camera.eyeposition[]\ndepth = map(x -> norm(x .- eyepos), hitpoints)\nmeshscatter!(ax, hitpoints, color=depth, colormap=[:gray, :black], markersize=0.01)\nmeshscatter!(ax, [centroid], color=:red, markersize=0.05)\nf\n\nThe red sphere marks the centroid - useful for camera placement and focus calculations.","title":"Centroid Calculation"},{"category":"section","location":"bvh_hit_tests_content.html#TLAS-Hit-Testing:-closest_hit-vs-any_hit","page":"TLAS Hit Testing: closest_hit vs any_hit","text":"This document tests and visualizes the difference between closest_hit and any_hit functions in the TLAS implementation using the trace_rays API.","title":"TLAS Hit Testing: closest_hit vs any_hit"},{"category":"section","location":"bvh_hit_tests_content.html#Test-Setup","page":"TLAS Hit Testing: closest_hit vs any_hit","text":"using Raycore, GeometryBasics, LinearAlgebra\nusing WGLMakie\nusing Test\nusing Bonito\nimport KernelAbstractions as KA\n\n# Create a simple test scene with multiple overlapping primitives\nfunction create_test_scene()\n    # Three spheres at different distances along the Z-axis\n    sphere1 = normal_mesh(Sphere(Point3f(0, 0, 5), 1.0f0))   # Furthest\n    sphere2 = normal_mesh(Sphere(Point3f(0, 0, 3), 1.0f0))   # Middle\n    sphere3 = normal_mesh(Sphere(Point3f(0, 0, 1), 1.0f0))   # Closest\n\n    tlas = Raycore.TLAS(KA.CPU())\n    push!(tlas, sphere1)\n    push!(tlas, sphere2)\n    push!(tlas, sphere3)\n    sync!(tlas)\n    return tlas\nend\n\ntlas = create_test_scene()","title":"Test Setup"},{"category":"section","location":"bvh_hit_tests_content.html#Test-1:-Single-Ray-Through-Center","page":"TLAS Hit Testing: closest_hit vs any_hit","text":"Test a ray through the center that passes through all three spheres.\n\n# Create a ray with slight offset to avoid hitting triangle vertices exactly\ntest_ray = Raycore.Ray(o=Point3f(0.1, 0.1, -5), d=Vec3f(0, 0, 1))\n\n# Trace with closest_hit (default)\nresult_closest = trace_rays(tlas, [test_ray])\n\nfig = Figure()\n\n# Left: closest_hit visualization\nplot(fig[1, 1], result_closest; axis=(; show_axis=false))\nLabel(fig[0, 1], \"closest_hit\", fontsize=20, font=:bold, tellwidth=false)\n\nfig","title":"Test 1: Single Ray Through Center"},{"category":"section","location":"bvh_hit_tests_content.html#Test-2:-Multiple-Rays-from-Different-Positions","page":"TLAS Hit Testing: closest_hit vs any_hit","text":"Test multiple rays to ensure both functions work correctly.\n\n# Test rays from different angles (with slight offset to avoid vertex hits)\ntest_positions = map(p-> (p = p.-0.5; Point3f(p..., -5)), rand(Point2f, 10))\n# Create rays\nrays = [Raycore.Ray(o=pos, d=Vec3f(0, 0, 1)) for pos in test_positions]\n\n# Trace rays and visualize\nresult_multi = trace_rays(tlas, rays)\nplot(result_multi; axis=(;show_axis=false))","title":"Test 2: Multiple Rays from Different Positions"},{"category":"section","location":"bvh_hit_tests_content.html#Test-3:-Complex-Scene","page":"TLAS Hit Testing: closest_hit vs any_hit","text":"Demonstrate ray tracing through a complex scene with many overlapping objects.\n\n# Create a complex scene with overlapping geometry\nusing Random\nRandom.seed!(123)\n\ncomplex_tlas = Raycore.TLAS(KA.CPU())\n\n# Add some large overlapping spheres\npush!(complex_tlas, normal_mesh(Sphere(Point3f(0, 0, 10), 3.0f0)))\npush!(complex_tlas, normal_mesh(Sphere(Point3f(0.5, 0, 5), 0.5f0)))\npush!(complex_tlas, normal_mesh(Sphere(Point3f(-0.5, 0, 15), 1.5f0)))\n\n# Add many small spheres to create complex TLAS structure\nfor i in 1:30\n    x = randn() * 5\n    y = randn() * 5\n    z = rand(8.0:0.5:12.0)\n    r = 0.3 + rand() * 0.5\n    push!(complex_tlas, normal_mesh(Sphere(Point3f(x, y, z), Float32(r))))\nend\n\nsync!(complex_tlas)\n\n# Test rays\ntest_rays = map(rand(Point2f, 20)) do p\n    p = (p .* 14f0) .- 8f0\n    Raycore.Ray(o=Point3f(p..., -5), d=Vec3f(0, 0, 1))\nend\n\nresult = trace_rays(complex_tlas, test_rays)\n\nfig = Figure()\nplot(fig[1, 1], result; axis=(; show_axis=false))\nLabel(fig[0, 1], \"closest_hit\", tellwidth=false)\n\nfig\n\n\nKey Findings:\n\nclosest_hit continues searching and updates ray's t_max to find the nearest intersection\nany_hit exits on the first intersection during TLAS traversal (useful for shadow rays)\nBoth always agree on whether a hit occurred (hit vs miss)\nany_hit is typically faster than closest_hit due to early termination","title":"Test 3: Complex Scene"},{"category":"section","location":"bvh_hit_tests_content.html#Performance-Comparison","page":"TLAS Hit Testing: closest_hit vs any_hit","text":"Compare the performance of closest_hit vs any_hit.\n\nfunction render_io(obj)\n    io = IOBuffer()\n    show(io, MIME\"text/plain\"(), obj)\n    printer = BonitoBook.HTMLPrinter(io; root_tag = \"span\")\n    str = sprint(io -> show(io, MIME\"text/html\"(), printer))\n    DOM.pre(HTML(str); style=\"font-size: 10px\")\nend\n\nusing BenchmarkTools\nusing Adapt\n\ntest_ray = Raycore.Ray(o=Point3f(0.1, 0.1, -5), d=Vec3f(0, 0, 1))\nstatic_tlas = Adapt.adapt(KA.CPU(), tlas)\n\n# Benchmark closest_hit\nclosest_time = @benchmark Raycore.closest_hit($static_tlas, $test_ray)\n\n# Benchmark any_hit\nany_time = @benchmark Raycore.any_hit($static_tlas, $test_ray)\n\n\nperf_table = map([\n    (\"closest_hit\", closest_time),\n    (\"any_hit\", any_time),\n]) do (method, time_us)\n    (Method = method, Time_μs = render_io(time_us))\nend\nBonito.Table(perf_table)","title":"Performance Comparison"},{"category":"section","location":"bvh_hit_tests_content.html#Summary","page":"TLAS Hit Testing: closest_hit vs any_hit","text":"This document demonstrated:\n\ntrace_rays - A convenient function for tracing rays against a TLAS and collecting results for visualization\nReturns a RayIntersectionResult bundling rays, hit data, and the TLAS\nAutomatically builds a StaticTLAS for traversal\nMakie visualization recipe - Automatic visualization via plot(result)\nAutomatically renders TLAS geometry, rays, and hit points\nCustomizable colors, transparency, markers, and labels\nWorks with any Makie backend (GLMakie, WGLMakie, CairoMakie)\nclosest_hit correctly identifies the nearest intersection among multiple overlapping primitives\nReturns: (hit_found::Bool, triangle::Triangle, distance::Float32, bary_coords::SVector{3,Float32}, instance_id::UInt32)\nUse sum(bary_coords .* triangle.vertices) to convert to world-space hit point\nany_hit efficiently determines if any intersection exists, exiting early\nReturns: Same format as closest_hit\nCan exit early on first hit found, making it faster for occlusion testing\nBoth functions handle miss cases correctly (returning hit_found=false)\nany_hit is typically faster than closest_hit due to early termination\n\nAll tests passed! ✓","title":"Summary"},{"category":"section","location":"hw_acceleration.html#Hardware-Ray-Tracing-with-Lava","page":"Hardware RT Acceleration","text":"Modern GPUs include dedicated ray tracing hardware (RT cores on NVIDIA, Ray Accelerators on AMD) that can traverse BVH structures and test ray-triangle intersections in fixed-function silicon. This tutorial shows how to use hardware acceleration with Raycore via the Lava.jl Vulkan backend.\n\nThe demo builds the same scene twice — once into a software Raycore.TLAS, once into a hardware Lava.HWTLAS — traces primary camera rays through both, and verifies the depth buffers agree.","title":"Hardware Ray Tracing with Lava"},{"category":"section","location":"hw_acceleration.html#When-to-pick-Raycore.TLAS-vs.-Lava.HWTLAS","page":"Hardware RT Acceleration","text":"Aspect Raycore.TLAS Lava.HWTLAS\nBackend any KA backend (CUDA, AMDGPU, Metal, Lava) Lava + Vulkan RT only\nBVH software (BVH4 / instanced BVH) VkAccelerationStructureKHR\nClosest-hit kernel KA @kernel, in-line Raycore.closest_hit(bvh, ray) vkCmdTraceRaysKHR over a ray batch\nDispatch overhead low, KA launch very low, pre-baked SBT\nUse when portability / non-Vulkan backend / no RT hardware max perf on Vulkan RT hardware\n\nBoth types satisfy Raycore.AbstractAccel — push!, delete!, update_transform!, sync!, n_instances, n_geometries, wait_for_gpu! work identically. The HW path uses a batched dispatch (Lava.trace_closest_hits!) instead of a per-thread closest_hit call inside a KA kernel.","title":"When to pick Raycore.TLAS vs. Lava.HWTLAS"},{"category":"section","location":"hw_acceleration.html#When-Hardware-RT-Helps","page":"Hardware RT Acceleration","text":"Hardware RT gives the biggest speedups on scenes with:\n\nHigh triangle counts — RT cores traverse the BVH in fixed-function hardware\nComplex occlusion — interior scenes, overlapping geometry, more traversal steps per ray\nSimple shading — when BVH traversal dominates, not material evaluation\n\nFor trivial scenes the software BVH already runs at GPU memory bandwidth, so the win is modest. The demo below uses ~48k triangles which is enough to see HW pull ahead but small enough to fit in a tutorial.\n\nHardware RT requires a Vulkan-capable GPU with VK_KHR_ray_tracing_pipeline. NVIDIA RTX (Turing+), AMD RDNA 2+, and Intel Arc all support it.","title":"When Hardware RT Helps"},{"category":"section","location":"hw_acceleration.html#Setup","page":"Hardware RT Acceleration","text":"using Raycore, GeometryBasics, LinearAlgebra\nusing Lava\nusing WGLMakie\nusing Adapt\nimport KernelAbstractions as KA\nusing KernelAbstractions: @kernel, @index, @Const\n\ndevice = Lava.LavaBackend()\n\nLava backend active — Vulkan device with RT support.\n\nLavaBackend is a KernelAbstractions backend that compiles @kernel code through Lava's SPIR-V compiler. It's also the device that owns Vulkan acceleration structures, so SW and HW share the same GPU context.","title":"Setup"},{"category":"section","location":"hw_acceleration.html#Building-a-scene-twice-—-software-and-hardware","page":"Hardware RT Acceleration","text":"Build a small scene of tessellated spheres on a floor — enough triangles for the BVH traversal cost to matter. Both Raycore.TLAS and Lava.HWTLAS ingest plain GeometryBasics.Mesh objects through push!, so the same meshes go into both.\n\nfunction build_meshes()\n    floor = GeometryBasics.normal_mesh(Rect3f(Vec3f(-3, -3, -0.01), Vec3f(6, 6, 0.01)))\n    sphere_centers = Point3f[]\n    for i in -2:2, j in -2:2\n        push!(sphere_centers, Point3f(Float32(i)*0.9f0, Float32(j)*0.9f0, 0.4f0))\n    end\n    spheres = [GeometryBasics.normal_mesh(Tesselation(Sphere(c, 0.3f0), 32))\n               for c in sphere_centers]\n    return [floor; spheres]\nend\n\nall_meshes = build_meshes()\ntotal_tris = sum(length(GeometryBasics.faces(m)) for m in all_meshes)\n\nsw_tlas = Raycore.TLAS(device)\nhwtlas  = Lava.HWTLAS(device)\n\nfor (i, m) in enumerate(all_meshes)\n    push!(sw_tlas, m)\n    push!(hwtlas, m; instance_id=UInt32(i))\nend\n\nRaycore.sync!(sw_tlas)\nRaycore.sync!(hwtlas)\n\nScene built\n\n meshes instances triangles\nRaycore.TLAS 26 26 48 062\nLava.HWTLAS 26 26 48 062\n\nsync! uploads the meshes and builds the acceleration structures. For Raycore.TLAS that means GPU LBVH builds (one BLAS per mesh + a TLAS over instances). For Lava.HWTLAS it means vkCmdBuildAccelerationStructuresKHR calls plus instance-table allocation.","title":"Building a scene twice — software and hardware"},{"category":"section","location":"hw_acceleration.html#Tracing-primary-rays-both-ways","page":"Hardware RT Acceleration","text":"Generate one camera ray per pixel. The SW path uses Raycore.Ray (origin + direction), the HW path uses Raycore.RTRay (origin + dir + tmin/tmax, 32-byte struct that matches Vulkan's VkRayTracingShaderRecordKHR layout).\n\nconst W, H = 256, 192\n\ncam_pos    = Point3f(0, -3.5, 1.6)\ncam_target = Point3f(0, 0, 0.3)\ncam_up     = Point3f(0, 0, 1)\n\nforward = normalize(cam_target - cam_pos)\nright   = normalize(cross(forward, cam_up))\nup      = cross(right, forward)\naspect  = Float32(W / H)\nfocal   = 1.0f0 / tan(deg2rad(45.0f0 / 2))\n\nfunction build_rays(W, H, cam_pos, forward, right, up, aspect, focal)\n    rays_sw = Vector{Raycore.Ray}(undef, W*H)\n    rays_hw = Vector{Raycore.RTRay}(undef, W*H)\n    for y in 1:H, x in 1:W\n        u = (2.0f0 * (Float32(x) - 0.5f0) / Float32(W) - 1.0f0)\n        v = (1.0f0 - 2.0f0 * (Float32(y) - 0.5f0) / Float32(H))\n        d = normalize(forward * focal + right * (u * aspect) + up * v)\n        i = (y - 1) * W + x\n        rays_sw[i] = Raycore.Ray(o=cam_pos, d=Vec3f(d))\n        rays_hw[i] = Raycore.RTRay(cam_pos[1], cam_pos[2], cam_pos[3], 0f0,\n                                    d[1], d[2], d[3], 1f3)\n    end\n    rays_sw, rays_hw\nend\n\nrays_sw, rays_hw = build_rays(W, H, cam_pos, forward, right, up, aspect, focal)\n\n# ---- SW path: KA kernel calls Raycore.closest_hit per pixel\n@kernel function depth_kernel_sw!(depth, @Const(bvh), @Const(rays))\n    i = @index(Global, Linear)\n    @inbounds if i <= length(rays)\n        ray = rays[i]\n        hit_found, _, dist, _, _ = Raycore.closest_hit(bvh, ray)\n        depth[i] = hit_found ? dist : -1f0\n    end\nend\n\nsw_static    = Adapt.adapt(device, sw_tlas)              # StaticTLAS for kernels\nrays_sw_gpu  = Lava.LavaArray(rays_sw)\ndepth_sw_gpu = Lava.LavaArray(zeros(Float32, W*H))\n\nsw_kernel = depth_kernel_sw!(device, 64)\nsw_kernel(depth_sw_gpu, sw_static, rays_sw_gpu, ndrange=W*H)\nKA.synchronize(device)\ndepth_sw = Array(depth_sw_gpu)\n\n# ---- HW path: batched trace_closest_hits! dispatches vkCmdTraceRaysKHR\nrays_hw_gpu = Lava.LavaArray(rays_hw)\nhits_hw     = Lava.LavaArray(fill(Raycore.RTHitResult(0,0,0,0,0,0,0,0), W*H))\n\nLava.trace_closest_hits!(hits_hw, rays_hw_gpu, hwtlas.hw_accel, length(rays_hw))\nRaycore.wait_for_gpu!(hwtlas)\n\ndepth_hw = Float32[h.hit == UInt32(1) ? h.t : -1f0 for h in Array(hits_hw)]\n\n# ---- Compare\nhit_mask_sw  = depth_sw .> 0\nhit_mask_hw  = depth_hw .> 0\ndisagree     = count(hit_mask_sw .!= hit_mask_hw)\nshared       = hit_mask_sw .& hit_mask_hw\nmax_abs_diff = maximum(abs.(depth_sw[shared] .- depth_hw[shared]))\n\nPixel-wise agreement\n\nhit-mask disagreement: 0 pixels out of 49 152\nmax abs depth diff on shared hits: 1.29e-5\n\nSub-1e-4 tolerance is the expected noise floor — both paths use the same Möller–Trumbore-style intersection but with slightly different rounding (the HW path goes through Vulkan's intersection shader, the SW path through Raycore's kernel).","title":"Tracing primary rays both ways"},{"category":"section","location":"hw_acceleration.html#How-the-two-paths-line-up","page":"Hardware RT Acceleration","text":"Software BVH (SW):                Hardware RT (HW):\n┌──────────────────┐              ┌──────────────────┐\n│ KA @kernel       │              │ Build RTRay      │\n│  per pixel       │              │   batch          │\n│                  │              └────────┬─────────┘\n│ Raycore.         │                       │\n│   closest_hit(   │              ┌────────▼─────────┐\n│     bvh, ray)    │              │ trace_closest_   │\n│                  │              │   hits! (one     │\n│ writes depth[i]  │              │   vkCmdTraceRays │\n└──────────────────┘              │   call)          │\n                                  └────────┬─────────┘\n                                           │\n                                  ┌────────▼─────────┐\n                                  │ RTHitResult[]    │\n                                  │ — t, prim_id,    │\n                                  │   bary, ...      │\n                                  └──────────────────┘\n\nIn the SW path the kernel is fully programmable — anything you can write inside a @kernel function (shadow rays, multi-bounce, custom intersection) works the same way. In the HW path the traversal is fixed-function: rays go in as RTRay, hit results come out as RTHitResult. The raygen / closest-hit / miss shaders are pre-baked and dispatched as one Vulkan call per ray batch.","title":"How the two paths line up"},{"category":"section","location":"hw_acceleration.html#Visualize-and-time","page":"Hardware RT Acceleration","text":"to_disp(d) = d > 0 ? d : NaN32\nimg_sw = reshape(depth_sw, W, H) |> permutedims |> x -> to_disp.(x)\nimg_hw = reshape(depth_hw, W, H) |> permutedims |> x -> to_disp.(x)\n\n# Warm-up + 5-shot minimum timing\nfunction time_sw()\n    KA.synchronize(device)\n    t = @elapsed begin\n        sw_kernel(depth_sw_gpu, sw_static, rays_sw_gpu, ndrange=W*H)\n        KA.synchronize(device)\n    end\n    return t\nend\n\nfunction time_hw()\n    Raycore.wait_for_gpu!(hwtlas)\n    t = @elapsed begin\n        Lava.trace_closest_hits!(hits_hw, rays_hw_gpu, hwtlas.hw_accel, length(rays_hw))\n        Raycore.wait_for_gpu!(hwtlas)\n    end\n    return t\nend\n\ntime_sw(); time_sw(); time_hw(); time_hw()  # warm\nt_sw = minimum(time_sw() for _ in 1:5)\nt_hw = minimum(time_hw() for _ in 1:5)\n\nfig = Figure(size=(900, 380))\nax1 = Axis(fig[1, 1], title=\"SW (Raycore.TLAS)  $(round(t_sw*1000, digits=2)) ms\",\n           aspect=DataAspect())\nax2 = Axis(fig[1, 2], title=\"HW (Lava.HWTLAS)  $(round(t_hw*1000, digits=2)) ms\",\n           aspect=DataAspect())\nhidedecorations!(ax1); hidedecorations!(ax2)\nheatmap!(ax1, img_sw, colormap=:viridis)\nheatmap!(ax2, img_hw, colormap=:viridis)\nfig\n\n(Image: SW vs HW depth heatmaps)\n\nThe two heatmaps are visually indistinguishable — the depth comparison cell above quantifies that. The timing ratio depends on triangle count, ray coherence, and GPU; the only honest way to know what your scene needs is to measure both.","title":"Visualize and time"},{"category":"section","location":"hw_acceleration.html#Lifetime-and-memory-management","page":"Hardware RT Acceleration","text":"sync!(hwtlas) owns hwtlas.static_tlas. Consumers re-read it (or call Adapt.adapt(backend, hwtlas)) per dispatch — do NOT cache across mutations.\n\nsync! does not block the CPU. Backend-internal timeline tracking (Lava's bq.deferred_as_frees) handles the \"still in flight\" case when old acceleration-structure buffers are dropped. If you need a CPU-blocking drain — e.g. before tear-down or between benchmark phases — call Raycore.wait_for_gpu!(hwtlas) explicitly.","title":"Lifetime and memory management"},{"category":"section","location":"hw_acceleration.html#Direct-HWTLAS-usage","page":"Hardware RT Acceleration","text":"The cells above already show the full direct-API path. The minimum is:\n\nusing Raycore, Lava, GeometryBasics, LinearAlgebra\nusing Raycore: RTRay, RTHitResult\n\ndevice = Lava.LavaBackend()\nhwtlas = Lava.HWTLAS(device)\n\nmesh = GeometryBasics.normal_mesh(Sphere(Point3f(0, 0, 2), 1.0f0))\npush!(hwtlas, mesh; instance_id=UInt32(1))\nRaycore.sync!(hwtlas)\n\nrays = Lava.LavaArray([RTRay(0,0,5, 0,  0,0,-1, 1f3)])\nhits = Lava.LavaArray(fill(RTHitResult(0,0,0,0,0,0,0,0), 1))\nLava.trace_closest_hits!(hits, rays, hwtlas.hw_accel, 1)\nRaycore.wait_for_gpu!(hwtlas)\n\nHardwareAccel (hwtlas.hw_accel) is the lower-level handle if you need direct control of the pipeline / SBT or want to install a custom any-hit shader (Lava.set_anyhit_pipeline!).","title":"Direct HWTLAS usage"},{"category":"section","location":"hw_acceleration.html#RT-shader-intrinsics","page":"Hardware RT Acceleration","text":"If you write your own raygen / closest-hit / miss shaders in Lava, the RT intrinsics use the lava_rt_* naming convention — no accel argument since the SBT wires up the hardware automatically:\n\nRaycore.rt_* (generic) lava_rt_* (Lava-specific)\nRaycore.rt_primitive_id(accel) lava_rt_primitive_id()\nRaycore.rt_instance_id(accel) lava_rt_instance_id()\nRaycore.rt_instance_custom_index(accel) lava_rt_instance_custom_index()\nRaycore.rt_launch_id_x(accel) lava_rt_launch_id_x()\nRaycore.rt_trace_ray!(accel, ...) lava_rt_trace_ray(...)\nRaycore.rt_ignore_intersection(accel) lava_rt_ignore_intersection()\nRaycore.rt_payload_store!(accel, val, slot) lava_rt_payload_store_f32_at(val, slot)\nRaycore.rt_payload_load(accel, slot) lava_rt_payload_load_f32_at(slot)\n\nThe pre-baked shaders shipped with Lava.HardwareAccel (raygen / closest-hit / miss for RTHitResult payload) are defined in Lava/src/raytracing/raycore_compat.jl as a reference implementation.","title":"RT shader intrinsics"},{"category":"section","location":"bvh_hit_tests.html#BVH-Hit-tests","page":"BVH Hit Tests","text":"book_app # hide","title":"BVH Hit tests"},{"category":"section","location":"raytracing_tutorial_content.html#Ray-Tracing-in-one-Hour","page":"Ray Tracing in one Hour","text":"Analogous to the famous Ray Tracing in one Weekend, this tutorial uses Raycore to do the hard work of performant ray triangle intersection and therefore get a high performing ray tracer in a much shorter time. We'll start with the absolute basics and progressively add features until we have a ray tracer that produces beautiful images with shadows, materials, and reflections.","title":"Ray Tracing in one Hour"},{"category":"section","location":"raytracing_tutorial_content.html#Setup","page":"Ray Tracing in one Hour","text":"using Raycore, GeometryBasics, LinearAlgebra\nusing Colors, ImageShow, WGLMakie\nusing MeshIO\nusing BenchmarkTools\n\nReady to go! We have:\n\nRaycore for fast ray-triangle intersections\nGeometryBasics for geometry primitives\nColors and ImageShow for displaying rendered images\nMeshIO for loading the cat data","title":"Setup"},{"category":"section","location":"raytracing_tutorial_content.html#Part-1:-Our-Scene,-The-Makie-Cat","page":"Ray Tracing in one Hour","text":"Let's create a fun scene that we'll use throughout this tutorial.\n\n# Load the cat model and rotate it to face the camera\ncat_mesh = Makie.loadasset(\"cat.obj\")\nangle = deg2rad(150f0)\nrotation = Makie.Quaternionf(0, sin(angle/2), 0, cos(angle/2))\nrotated_coords = [rotation * Point3f(v) for v in coordinates(cat_mesh)]\n\n# Get bounding box and translate cat to sit on the floor\ncat_bbox = Rect3f(rotated_coords)\nfloor_y = -1.5f0\ncat_offset = Vec3f(0, floor_y - cat_bbox.origin[2], 0)\n\ncat_mesh = GeometryBasics.normal_mesh(\n    [v + cat_offset for v in rotated_coords],\n    faces(cat_mesh)\n)\n\n# Create a simple room: floor, back wall, and side wall\nfloor = normal_mesh(Rect3f(Vec3f(-5, -1.5, -2), Vec3f(10, 0.01, 10)))\nback_wall = normal_mesh(Rect3f(Vec3f(-5, -1.5, 8), Vec3f(10, 5, 0.01)))\nleft_wall = normal_mesh(Rect3f(Vec3f(-5, -1.5, -2), Vec3f(0.01, 5, 10)))\n\n# Add a couple of spheres for visual interest\nsphere1 = Tesselation(Sphere(Point3f(-2, -1.5 + 0.8, 2), 0.8f0), 64)\nsphere2 = Tesselation(Sphere(Point3f(2, -1.5 + 0.6, 1), 0.6f0), 64)\n\n# Build our TLAS acceleration structure\nscene_geometry = [cat_mesh, floor, back_wall, left_wall,\n    normal_mesh(sphere1), normal_mesh(sphere2)]\nbvh = Raycore.TLAS(scene_geometry, (mesh_idx, tri_idx) -> UInt32(mesh_idx))\nmd\"**TLAS built**\"","title":"Part 1: Our Scene, The Makie Cat"},{"category":"section","location":"raytracing_tutorial_content.html#Part-2:-Helper-Functions-Building-Blocks","page":"Ray Tracing in one Hour","text":"Let's define reusable helper functions we'll use throughout:\n\n# Compute interpolated normal at hit point\nfunction compute_normal(triangle, bary_coords)\n    v0, v1, v2 = Raycore.normals(triangle)\n    u, v, w = bary_coords[1], bary_coords[2], bary_coords[3]\n    return Vec3f(normalize(v0 * u + v1 * v + v2 * w))\nend\n\n# Generate camera ray for a pixel with optional jitter\nfunction camera_ray(x, y, width, height, camera_pos, focal_length, aspect; jitter=Vec2f(0))\n    ndc_x = (2.0f0 * (Float32(x) - 0.5f0 + jitter[1]) / Float32(width) - 1.0f0) * aspect\n    ndc_y = 1.0f0 - 2.0f0 * (Float32(y) - 0.5f0 + jitter[2]) / Float32(height)\n    direction = normalize(Vec3f(ndc_x, ndc_y, focal_length))\n    return Raycore.Ray(o=camera_pos, d=direction)\nend\n\n# Convert between color representations\nto_vec3f(c::RGB) = Vec3f(c.r, c.g, c.b)\nto_rgb(v::Vec3f) = RGB{Float32}(v...)","title":"Part 2: Helper Functions - Building Blocks"},{"category":"section","location":"raytracing_tutorial_content.html#Part-3:-The-Simplest-Ray-Tracer-Depth-Visualization","page":"Ray Tracing in one Hour","text":"We're using one main function to shoot rays for each pixel. For simplicity, we already added multisampling and simple multi threading, to enjoy smoother images and faster rendering times throughout the tutorial. Read the GPU tutorial how to further improve the performance of this simple, not yet optimal kernel.\n\nfunction trace(f, bvh; width=700, height=300,\n               camera_pos=Point3f(0, -0.9, -2.5), fov=45.0f0,\n               sky_color=RGB{Float32}(0.5f0, 0.7f0, 1.0f0),\n               samples=1, ctx=nothing)\n    img = Matrix{RGB{Float32}}(undef, height, width)\n    aspect = Float32(width / height)\n    focal_length = 1.0f0 / tan(deg2rad(fov / 2))\n\n    Threads.@threads for y in 1:height\n        for x in 1:width\n            color_sum = Vec3f(0)\n            for _ in 1:samples\n                jitter = samples > 1 ? rand(Vec2f) : Vec2f(0)\n                # Calculate the ray shooting from the camera pixel into the scene\n                ray = camera_ray(x, y, width, height, camera_pos, focal_length, aspect; jitter)\n                hit_found, triangle, distance, bary_coords, _ = Raycore.closest_hit(bvh, ray)\n                color = if hit_found\n                    to_vec3f(f(bvh, ctx, triangle, distance, bary_coords, ray))\n                else\n                    to_vec3f(sky_color)\n                end\n                color_sum += color\n            end\n\n            img[y, x] = to_rgb(color_sum / samples)\n        end\n    end\n    return img\nend\n\n# Visualize depth\ndepth_kernel(bvh, ctx, tri, dist, bary, ray) = RGB(1.0f0 - min(dist / 10.0f0, 1.0f0))\n\n@time trace(depth_kernel, bvh, samples=16)\n\nFirst render! Depth visualization shows distance to surfaces. Much faster with threading and smoother with multi-sampling!","title":"Part 3: The Simplest Ray Tracer - Depth Visualization"},{"category":"section","location":"raytracing_tutorial_content.html#Part-5:-Lighting-with-Hard-Shadows","page":"Ray Tracing in one Hour","text":"Let's add lighting and shadows using a reusable lighting function:\n\n# Reusable lighting function with optional shadow sampling\nfunction compute_light(\n        bvh, point, normal, light_pos, light_intensity, light_color; shadow_samples=1)\n\n    light_vec = light_pos - point\n    light_dist = norm(light_vec)\n    light_dir = light_vec / light_dist\n\n    diffuse = max(0.0f0, dot(normal, light_dir))\n\n    # Shadow testing with optional soft shadows\n    shadow_factor = 0.0f0\n    light_radius = 0.2f0  # Size of area light for soft shadows\n\n    for _ in 1:shadow_samples\n        # For shadow_samples=1, this is just the light position (hard shadow)\n        # For shadow_samples>1, we sample random points on a disk (soft shadow)\n        if shadow_samples > 1\n            # Random point on disk perpendicular to light direction\n            offset = (rand(Vec3f) .* 2.0f0 .- 1.0f0) * light_radius\n            offset = offset - light_dir * dot(offset, light_dir)\n            shadow_target = light_pos + offset\n        else\n            shadow_target = light_pos\n        end\n\n        shadow_vec = shadow_target - point\n        shadow_dist = norm(shadow_vec)\n        shadow_dir = normalize(shadow_vec)\n\n        shadow_ray = Raycore.Ray(o=point + normal * 0.001f0, d=shadow_dir)\n        shadow_hit, _, hit_dist, _, _ = Raycore.any_hit(bvh, shadow_ray)\n\n        if !shadow_hit || hit_dist >= shadow_dist\n            shadow_factor += 1.0f0\n        end\n    end\n    shadow_factor /= shadow_samples\n\n    # Compute final light contribution\n    attenuation = light_intensity / (light_dist * light_dist)\n    return to_vec3f(light_color) * (diffuse * attenuation * shadow_factor)\nend\n\nfunction shadow_kernel(bvh, ctx, tri, dist, bary, ray; shadow_samples=1)\n    hit_point = ray.o + ray.d * dist\n    normal = compute_normal(tri, bary)\n    # Single point light\n    light_pos = Point3f(3, 4, -2)\n    light_intensity = 50.0f0\n    light_color = RGB{Float32}(1.0f0, 0.9f0, 0.8f0)\n    # Hard shadows (shadow_samples=1)\n    light_contrib = compute_light(\n        bvh, hit_point, normal, light_pos, light_intensity, light_color;\n        shadow_samples=shadow_samples\n    )\n    ambient = 0.1f0\n\n    brightness = ambient .+ light_contrib\n    return to_rgb(brightness)\nend\n\ntrace(shadow_kernel, bvh, samples=4)\n\nHard shadows working! Scene has realistic lighting with sharp shadow edges.","title":"Part 5: Lighting with Hard Shadows"},{"category":"section","location":"raytracing_tutorial_content.html#Part-6:-Soft-Shadows","page":"Ray Tracing in one Hour","text":"Now let's make shadows more realistic by sampling the light as an area light:\n\ntrace((args...)-> shadow_kernel(args...; shadow_samples=8), bvh, samples=8)\n\nSoft shadows! Much more realistic with smooth penumbra edges.","title":"Part 6: Soft Shadows"},{"category":"section","location":"raytracing_tutorial_content.html#Part-7:-Materials-and-Multiple-Lights","page":"Ray Tracing in one Hour","text":"Time to add color and multiple lights! To associate materials with geometry, we need to rebuild the TLAS with metadata that links each triangle to its material.","title":"Part 7: Materials and Multiple Lights"},{"category":"section","location":"raytracing_tutorial_content.html#Triangle-Metadata","page":"Ray Tracing in one Hour","text":"When building a TLAS, you can pass a metadata_fn(mesh_idx, tri_idx) that assigns custom data to each triangle. This metadata is stored in triangle.metadata and returned with every ray hit. For materials, we use the mesh index as metadata:\n\nstruct PointLight\n    position::Point3f\n    intensity::Float32\n    color::RGB{Float32}\nend\n\nstruct Material\n    base_color::RGB{Float32}\n    metallic::Float32\n    roughness::Float32\nend\n\nstruct RenderContext\n    lights::Vector{PointLight}\n    materials::Vector{Material}\n    ambient::Float32\nend\n\n# Define materials for each mesh (order matches scene_geometry)\nmaterials = [\n    Material(RGB(0.8f0, 0.6f0, 0.4f0), 0.0f0, 0.8f0),  # 1: cat\n    Material(RGB(0.3f0, 0.5f0, 0.3f0), 0.0f0, 0.9f0),  # 2: floor\n    Material(RGB(0.8f0, 0.6f0, 0.5f0), 0.8f0, 0.05f0), # 3: back wall\n    Material(RGB(0.7f0, 0.7f0, 0.8f0), 0.0f0, 0.8f0),  # 4: left wall\n    Material(RGB(0.9f0, 0.9f0, 0.9f0), 0.8f0, 0.02f0), # 5: sphere1 - metallic\n    Material(RGB(0.3f0, 0.6f0, 0.9f0), 0.5f0, 0.3f0),  # 6: sphere2 - semi-metallic\n]\n\n# Rebuild TLAS with material indices as metadata\n# The metadata_fn receives (mesh_idx, tri_idx) and returns data stored per-triangle\nbvh = Raycore.TLAS(scene_geometry, (mesh_idx, tri_idx) -> UInt32(mesh_idx))\n\n# Create lights\nlights = [\n    PointLight(Point3f(3, 4, -2), 50.0f0, RGB(1.0f0, 0.9f0, 0.8f0)),\n    PointLight(Point3f(-3, 2, 0), 20.0f0, RGB(0.7f0, 0.8f0, 1.0f0)),\n    PointLight(Point3f(0, 5, 5), 15.0f0, RGB(1.0f0, 1.0f0, 1.0f0))\n]\n\nctx = RenderContext(lights, materials, 0.1f0)\nnothing\n\nNow when a ray hits a triangle, we can look up its material using triangle.metadata:\n\nmat = ctx.materials[triangle.metadata]  # Get material for hit triangle\n\n# Compute lighting from all lights - reusing our compute_light function!\nfunction compute_multi_light(bvh, ctx, point, normal, mat; shadow_samples=1)\n    base_color = to_vec3f(mat.base_color)\n    total_color = base_color * ctx.ambient\n\n    for light in ctx.lights\n        light_contrib = compute_light(bvh, point, normal, light.position, light.intensity, light.color, shadow_samples=shadow_samples)\n        total_color += base_color .* light_contrib\n    end\n\n    return total_color\nend\n\nfunction material_kernel(bvh, ctx, tri, dist, bary, ray)\n    hit_point = ray.o + ray.d * dist\n    normal = compute_normal(tri, bary)\n    # Look up material using triangle's metadata (mesh index we stored during BVH construction)\n    mat = ctx.materials[tri.metadata]\n\n    color = compute_multi_light(bvh, ctx, hit_point, normal, mat, shadow_samples=2)\n    return to_rgb(color)\nend\n\ntrace(material_kernel, bvh, samples=4, ctx=ctx)\n\nColorful scene with soft shadows from multiple lights! Each object has its own material.","title":"Triangle Metadata"},{"category":"section","location":"raytracing_tutorial_content.html#Part-8:-Reflections","page":"Ray Tracing in one Hour","text":"Add simple reflections for metallic surfaces:\n\nfunction reflective_kernel(bvh, ctx, tri, dist, bary, ray, sky_color)\n    hit_point = ray.o + ray.d * dist\n    normal = compute_normal(tri, bary)\n    mat = ctx.materials[tri.metadata]\n\n    # Direct lighting with soft shadows\n    direct_color = compute_multi_light(bvh, ctx, hit_point, normal, mat, shadow_samples=8)\n\n    # Reflections for metallic surfaces\n    if mat.metallic > 0.0f0\n        wo = -ray.d\n        reflect_dir = Raycore.reflect(wo, normal)\n\n        # Optional roughness\n        if mat.roughness > 0.0f0\n            offset = (rand(Vec3f) .* 2.0f0 .- 1.0f0) * mat.roughness\n            reflect_dir = normalize(reflect_dir + offset)\n        end\n\n        # Cast reflection ray\n        reflect_ray = Raycore.Ray(o=hit_point + normal * 0.001f0, d=reflect_dir)\n        refl_hit, refl_tri, refl_dist, refl_bary, _ = Raycore.closest_hit(bvh, reflect_ray)\n\n        reflection_color = if refl_hit\n            refl_point = reflect_ray.o + reflect_ray.d * refl_dist\n            refl_normal = compute_normal(refl_tri, refl_bary)\n            refl_mat = ctx.materials[refl_tri.metadata]\n            compute_multi_light(bvh, ctx, refl_point, refl_normal, refl_mat, shadow_samples=1)\n        else\n            to_vec3f(sky_color)\n        end\n\n        direct_color = direct_color * (1.0f0 - mat.metallic) + reflection_color * mat.metallic\n    end\n\n    return to_rgb(direct_color)\nend\n\nimg = trace(bvh, samples=16, ctx=ctx) do bvh, ctx, tri, dist, bary, ray\n    reflective_kernel(bvh, ctx, tri, dist, bary, ray, RGB(0.5f0, 0.7f0, 1.0f0))\nend\n\n# Tone mapping functions\nluminosity(c::RGB{T}) where {T} = (max(c.r, c.g, c.b) + min(c.r, c.g, c.b)) / 2.0f0\n\nfunction avg_lum(rgb_m, δ::Number=1f-10)\n    cumsum = 0.0f0\n    for pix in rgb_m\n        cumsum += log10(δ + luminosity(pix))\n    end\n    return 10^(cumsum / (prod(size(rgb_m))))\nend\n\nfunction tone_mapping(img; a=0.5f0, y=1.0f0, lum=avg_lum(img, 1f-10))\n    img_normalized = img .* a .* (1.0f0 / lum)\n    img_01 = map(col->mapc(c-> clamp(c, 0f0, 1f0), col), img_normalized)\n    ycorrected = map(col->mapc(c-> c^(1f0 / y), col), img_01)\n    return ycorrected\nend\n\ntone_mapping(img, a=0.38, y=1.0)\n\nFor performance type stability is a must! We can use JET to test if a function is completely type stable, which we also test in the Raycore tests for all functions.\n\nusing JET\n\n# Get test data\ntest_ray = camera_ray(350, 150, 700, 300, Point3f(0, -0.9, -2.5), 1.0f0 / tan(deg2rad(45.0f0 / 2)), Float32(700/300))\nhit_found, test_tri, test_dist, test_bary = Raycore.closest_hit(bvh, test_ray)\n\n# Check kernel type stability (filter to Main module to ignore Base internals)\n@test_opt depth_kernel(bvh, ctx, test_tri, test_dist, test_bary, test_ray)\n@test_opt shadow_kernel(bvh, ctx, test_tri, test_dist, test_bary, test_ray)\n@test_opt material_kernel(bvh, ctx, test_tri, test_dist, test_bary, test_ray)\n@test_opt reflective_kernel(bvh, ctx, test_tri, test_dist, test_bary, test_ray, RGB(0.5f0, 0.7f0, 1.0f0))\nnothing","title":"Part 8: Reflections"},{"category":"section","location":"raytracing_tutorial_content.html#Summary","page":"Ray Tracing in one Hour","text":"We built a complete ray tracer with:\n\nCore Features:\n\nTLAS acceleration for fast ray-scene intersections\nPerspective camera with configurable FOV\nSmooth shading from interpolated normals\nMulti-light system with distance attenuation\nSoft shadows using area light sampling (via compute_light with shadow_samples)\nMaterial system (base color, metallic, roughness)\nReflections with optional roughness\nACES tone mapping for HDR\n\nPerformance:\n\nMulti-threading for parallel rendering (introduced early!)\nMulti-sampling for anti-aliasing (introduced early!)\nType-stable kernels for optimal performance\nModular, reusable compute_light function - works for both hard and soft shadows\n\nKey Raycore Functions:\n\nRaycore.TLAS(meshes) - Build acceleration structure\nRaycore.TLAS(meshes, metadata_fn) - Build with custom per-triangle metadata\nRaycore.Ray(o=origin, d=direction) - Create ray\nRaycore.closest_hit(tlas, ray) - Find nearest intersection, returns (hit, triangle, distance, bary_coords, instance_id)\nRaycore.any_hit(tlas, ray) - Test for any intersection (fast shadow test)\nRaycore.reflect(wo, normal) - Compute reflection direction\ntriangle.metadata - Access custom data stored per-triangle\n\nKey Patterns:\n\nMaterial Scene Pattern - Associate materials with geometry using metadata:\n\n# Build TLAS with mesh index as metadata\ntlas = Raycore.TLAS(meshes, (mesh_idx, tri_idx) -> UInt32(mesh_idx))\n\n# In your shader, look up material from hit triangle\nmat = materials[triangle.metadata]\n\nReusable Lighting - The compute_light function handles both hard and soft shadows:\n\nshadow_samples=1 → hard shadows\nshadow_samples>1 → soft shadows\n\nThis shows how well-designed functions can handle multiple use cases cleanly!","title":"Summary"},{"category":"section","location":"gpu_raytracing_tutorial.html#Ray-Tracing-on-the-GPU","page":"Ray Tracing on the GPU","text":"In this tutorial, we'll take the ray tracer from the previous tutorial and port it to the GPU using KernelAbstractions.jl and a GPU backend of choice (CUDA.jl, AMDGPU.jl, OpenCL.jl, OneApi.jl, or Metal.jl). We'll explore three different kernel implementations, each with different optimization strategies, and benchmark their performance against each other.\n\nBy the end, you'll understand how to write efficient GPU kernels for ray tracing and the tradeoffs between different approaches!","title":"Ray Tracing on the GPU"},{"category":"section","location":"gpu_raytracing_tutorial.html#Setup","page":"Ray Tracing on the GPU","text":"using Raycore, GeometryBasics, LinearAlgebra\nusing Colors, ImageShow\nusing WGLMakie\nusing KernelAbstractions\nusing BenchmarkTools\n\nTo run things on the GPU with KernelAbstractions, you need to choose the correct package for your GPU and set the array type we use from there on.\n\n#using CUDA; GArray = CuArray; # For NVIDIA GPUS\n#using AMDGPU; GArray = ROCArray; # for AMD GPUs\n#using Metal; GArray = MtlArray; # for Apple hardware\n#using oneAPI; GArray = oneArray; # for intel\n# OpenCL with the pocl backend should work for most CPUs and some GPUs, but might not be as fast.\n# using pocl_jll, OpenCL; GArray = CLArray;\nGArray = Array # For the tutorial to run on CI we just use the CPU\n\nReady for GPU! We have:\n\nRaycore for fast ray-triangle intersections\nKernelAbstractions for portable GPU kernels (works with CUDA, AMD, Metal, oneAPI, and OpenCL)\nBenchmarkTools for performance comparison","title":"Setup"},{"category":"section","location":"gpu_raytracing_tutorial.html#Part-1:-Scene-Setup-(Same-as-CPU-Tutorial)","page":"Ray Tracing on the GPU","text":"Let's use the exact same scene as the CPU tutorial - the Makie cat with room geometry:\n\n# Load and prepare the cat model\ninclude(\"raytracing-core.jl\")\nbvh, ctx = example_scene()\nmd\"**Scene loaded: $(length(bvh.all_blas_prims)) triangles, $(length(ctx.materials)) materials**\"","title":"Part 1: Scene Setup (Same as CPU Tutorial)"},{"category":"section","location":"gpu_raytracing_tutorial.html#Part-2:-GPU-Kernel-Version-1-Basic-Naive-Approach","page":"Ray Tracing on the GPU","text":"The simplest GPU kernel - one thread per pixel:\n\nimport KernelAbstractions as KA\n\n# Basic kernel: one thread per pixel, straightforward implementation\n@kernel function raytrace_kernel_v1!(\n    img, @Const(bvh), @Const(ctx),\n    camera_pos, focal_length, aspect, sky_color, ::Val{NSamples}\n) where {NSamples}\n    # Get pixel coordinates\n    idx = @index(Global, Linear)\n    height, width = size(img)\n    # Convert linear index to 2D coordinates\n    x = ((idx - 1) % width) + 1\n    y = ((idx - 1) ÷ width) + 1\n    if x <= width && y <= height\n        # Generate camera ray and calculate a simple light model\n        color = Vec3f(0)\n        for i in 1:NSamples\n            color = color .+ sample_light(bvh, ctx, width, height, camera_pos, focal_length, aspect, x, y, sky_color)\n        end\n        @inbounds img[y, x] = to_rgb(color ./ NSamples)\n    end\nend\n\nThe trace_gpu function is a universal launcher that works with any of our kernels. It handles the backend-specific setup automatically using KernelAbstractions.jl:\n\nfunction trace_gpu(kernel, img, bvh, ctx;\n        camera_pos=Point3f(0, -0.9, -2.5), fov=45.0f0,\n        sky_color=RGB{Float32}(0.5f0,0.7f0,1.0f0),\n        samples_per_pixel=4,\n        ndrange=length(img), tilesize=nothing\n    )\n    height, width = size(img)\n    aspect = Float32(width / height)\n    focal_length = 1.0f0 / tan(deg2rad(fov / 2))\n\n    # KernelAbstractions automatically detects the backend (CPU/GPU) from the array type\n    backend = KA.get_backend(img)\n\n    # Create the kernel with or without tilesize (for workgroup configuration)\n    kernel! = isnothing(tilesize) ? kernel(backend) : kernel(backend, tilesize)\n\n    kernel!(img, bvh, ctx, camera_pos, focal_length, aspect, sky_color, Val(samples_per_pixel), ndrange=ndrange)\n\n    # Ensure GPU computation completes before returning\n    KA.synchronize(backend)\n    return img\nend\n\nKey KernelAbstractions.jl concepts:\n\nBackend detection: get_backend(array) automatically determines if we're using CPU, AMD GPU, NVIDIA GPU, etc.\nKernel compilation: kernel(backend) compiles the kernel for the specific backend\nWorkgroup configuration: Optional tilesize parameter controls thread organization\nThread indexing: Inside kernels, use @index(Global, Linear) or @index(Global, Cartesian) to get thread IDs\nSynchronization: synchronize(backend) ensures all GPU work completes before continuing\n\nLet's test kernel v1 on the CPU (yes, they always work with normal Arrays):\n\nimg = fill(RGBf(0, 0, 0), 400, 720)\nbench_kernel_cpu_v1 = @benchmark trace_gpu(raytrace_kernel_v1!, img, bvh, ctx)\nimg\n\nTo run things on the GPU, we simply convert the arrays to the GPU backend array type. to_gpu is a helper in Raycore to convert nested structs correctly for the kernel. It's not doing anything special, besides that struct of arrays need to be converted to device arrays and for pure arrays GPUArray(array) is enough.\n\nusing Raycore: to_gpu\nimg = fill(RGBf(0, 0, 0), 400, 720)\nimg_gpu = GArray(img);\nbvh_gpu = to_gpu(GArray, bvh);\nctx_gpu = to_gpu(GArray, ctx);\nbench_kernel_v1 = @benchmark trace_gpu(raytrace_kernel_v1!, img_gpu, bvh_gpu, ctx_gpu)\n# Bring back to CPU to display image\nArray(img_gpu)\n\nFirst GPU render! This is the simplest approach - one thread per pixel with no optimization.","title":"Part 2: GPU Kernel Version 1 - Basic Naive Approach"},{"category":"section","location":"gpu_raytracing_tutorial.html#Part-3:-Optimized-Kernel-Loop-Unrolling","page":"Ray Tracing on the GPU","text":"Loop overhead is significant on GPUs! Manually unrolling the sampling loop eliminates this overhead:\n\n# Optimized kernel: Unrolled sampling loop\n@kernel function raytrace_kernel_unrolled!(\n        img, @Const(bvh), @Const(ctx),\n        camera_pos, focal_length, aspect, sky_color, ::Val{NSamples}\n    ) where {NSamples}\n    idx = @index(Global, Linear)\n    height, width = size(img)\n    x = ((idx - 1) % width) + 1\n    y = ((idx - 1) ÷ width) + 1\n    if x <= width && y <= height\n        # ntuple with compile-time constant for unrolling\n        samples = ntuple(NSamples) do i\n            sample_light(bvh, ctx, width, height,\n                camera_pos, focal_length, aspect,\n                x, y, sky_color\n            )\n        end\n        color = mean(samples)\n        @inbounds img[y, x] = to_rgb(color)\n    end\nend\n\nbench_kernel_unrolled = @benchmark trace_gpu(raytrace_kernel_unrolled!, img_gpu, bvh_gpu, ctx_gpu)\nArray(img_gpu)\n\nThis eliminates branch overhead from loop conditions\nReduces register pressure\nBetter instruction-level parallelism\n1.39x faster than baseline!","title":"Part 3: Optimized Kernel - Loop Unrolling"},{"category":"section","location":"gpu_raytracing_tutorial.html#Part-4:-Tiled-Kernel-with-Optimized-Tile-Size","page":"Ray Tracing on the GPU","text":"The tile size dramatically affects performance. Let's use the optimal size discovered through benchmarking:\n\n# Tiled kernel with optimized tile size\n@kernel function raytrace_kernel_tiled!(\n    img, bvh, ctx,\n    camera_pos, focal_length, aspect, sky_color, ::Val{NSamples}\n) where {NSamples}\n    # Get tile and local coordinates\n    _tile_xy = @index(Group, Cartesian)\n    _local_xy = @index(Local, Cartesian)\n    _groupsize = @groupsize()\n\n    # Direct tuple unpacking is faster than Vec construction\n    tile_x, tile_y = Tuple(_tile_xy)\n    local_x, local_y = Tuple(_local_xy)\n    group_w, group_h = _groupsize\n\n    # Compute global pixel coordinates\n    x = (tile_x - 1) * group_w + local_x\n    y = (tile_y - 1) * group_h + local_y\n\n    height, width = size(img)\n    if x <= width && y <= height\n        samples = ntuple(NSamples) do i\n            sample_light(bvh, ctx, width, height,\n                camera_pos, focal_length, aspect,\n                x, y, sky_color\n            )\n        end\n        color = mean(samples)\n        @inbounds img[y, x] = to_rgb(color)\n    end\nend\nbench_kernel_tiled_32_16 = @benchmark trace_gpu(\n    $raytrace_kernel_tiled!, $img_gpu, $bvh_gpu, $ctx_gpu;\n    ndrange=size($img_gpu), tilesize=(32,16))\n\n# Benchmark two more important tile sizes for comparison\nbench_kernel_tiled_32_32 = @benchmark trace_gpu(\n    $raytrace_kernel_tiled!, $img_gpu, $bvh_gpu, $ctx_gpu;\n    ndrange=size($img_gpu), tilesize=(32,32))\n\nbench_kernel_tiled_8_8 = @benchmark trace_gpu(\n    $raytrace_kernel_tiled!, $img_gpu, $bvh_gpu, $ctx_gpu;\n    ndrange=size($img_gpu), tilesize=(8,8))\n\n# Use optimal tile size: (32, 16) - discovered through benchmarking!\nArray(img_gpu)\n\nTile size matters! With (32, 16) tiles, this kernel is 1.22x faster than baseline. With poor tile sizes like (8, 8), it can be 2.5x slower!","title":"Part 4: Tiled Kernel with Optimized Tile Size"},{"category":"section","location":"gpu_raytracing_tutorial.html#Part-5:-Wavefront-Path-Tracing","page":"Ray Tracing on the GPU","text":"The wavefront approach reorganizes ray tracing to minimize thread divergence by grouping similar work together. Instead of each thread handling an entire pixel's path, we separate the work into stages. Discussing the exact implementation is outside the scope of this tutorial, so we only include the finished renderer here:\n\ninclude(\"wavefront-renderer.jl\")\n\nLet's benchmark the wavefront renderer on both CPU and GPU:\n\n# CPU benchmark\nrenderer_cpu = WavefrontRenderer(img, bvh, ctx)\nbench_wavefront_cpu = @benchmark render!($renderer_cpu)\n\n# GPU benchmark\nrenderer_gpu = to_gpu(GArray, renderer_cpu)\nbench_wavefront_gpu = @benchmark render!($renderer_gpu)\n\nrenderer_gpu = to_gpu(GArray, WavefrontRenderer(img, bvh, ctx; samples_per_pixel=16))\nrender!(renderer_gpu)\n# Display result\nArray(renderer_gpu.framebuffer)\n\nWavefront benefits:\n\nReduces thread divergence by grouping similar work\nBetter memory access patterns\nScales well with scene complexity\nEnables advanced features like path tracing","title":"Part 5: Wavefront Path Tracing"},{"category":"section","location":"gpu_raytracing_tutorial.html#Part-6:-Comprehensive-Performance-Benchmarks","page":"Ray Tracing on the GPU","text":"Now let's compare all kernels including the wavefront renderer:\n\nbenchmarks = [\n    bench_kernel_v1, bench_kernel_cpu_v1, bench_kernel_unrolled,\n    bench_kernel_tiled_8_8, bench_kernel_tiled_32_16, bench_kernel_tiled_32_32,\n    bench_wavefront_cpu, bench_wavefront_gpu\n]\nlabels = [\n    \"Baseline\\n(gpu)\", \"Baseline\\n(cpu)\", \"Unrolled\",\n    \"Tiled\\n(8×8)\", \"Tiled\\n(32×16)\", \"Tiled\\n(32×32)\",\n    \"Wavefront\\n(cpu)\", \"Wavefront\\n(gpu)\"\n]\n\nfig, times, speedups = plot_kernel_benchmarks(benchmarks, labels)\n# save(data\"gpu-benchmarks.png\", fig; backend=Main.GLMakie)\n# We use the Fig from my local run, since on CI this won't show the differences\nDOM.img(src=Asset(data\"gpu-benchmarks.png\"), width=\"700px\")","title":"Part 6: Comprehensive Performance Benchmarks"},{"category":"section","location":"gpu_raytracing_tutorial.html#Next-Steps","page":"Ray Tracing on the GPU","text":"Add adaptive sampling (more samples only where needed)\nExplore shared memory optimizations for BVH traversal\nImplement streaming multisampling across frames","title":"Next Steps"},{"category":"section","location":"viewfactors.html#View-Factors-and-More","page":"View Factors and More","text":"book_app # hide","title":"View Factors and More"},{"category":"section","location":"gpu_raytracing.html#GPU-Ray-Tracing-with-Raycore","page":"GPU Ray Tracing Tutorial","text":"book_app # hide","title":"GPU Ray Tracing with Raycore"},{"category":"section","location":"index.html#Raycore.jl","page":"Home","text":"High-performance ray-triangle intersection engine with TLAS/BLAS acceleration for CPU and GPU.","title":"Raycore.jl"},{"category":"section","location":"index.html#Features","page":"Home","text":"Fast TLAS/BLAS acceleration for ray-triangle intersection\nCPU and GPU support via KernelAbstractions.jl\nMultiTypeSet: GPU-safe heterogeneous collections with compile-time type-stable dispatch for materials, textures, lights, etc.\nGPU TLAS: Raycore.TLAS is software, backend-agnostic (any KA backend). For hardware ray tracing on Vulkan, use Lava.HWTLAS — a drop-in AbstractAccel implemented via VK_KHR_ray_tracing_pipeline. See Hardware Ray Tracing with Lava.\nAnalysis tools: centroid calculation, illumination analysis, view factors for radiosity\nMakie integration for visualization","title":"Features"},{"category":"section","location":"index.html#Interactive-Examples","page":"Home","text":"","title":"Interactive Examples"},{"category":"section","location":"index.html#Hit-Tests-and-Basics","page":"Home","text":"Learn the basics of ray-triangle intersection, TLAS construction, and visualization.\n\n(Image: Basics)\n\nBVH Hit tests","title":"Hit Tests & Basics"},{"category":"section","location":"index.html#Ray-Tracing-Tutorial","page":"Home","text":"Build a complete ray tracer from scratch with shadows, materials, reflections, and tone mapping.\n\n(Image: Ray Tracing)\n\nRay Tracing with Raycore","title":"Ray Tracing Tutorial"},{"category":"section","location":"index.html#GPU-Ray-Tracing-Tutorial","page":"Home","text":"Port the ray tracer to the GPU with KernelAbstractions.jl. Learn about kernel optimization, loop unrolling, tiling, and wavefront rendering.\n\n(Image: GPU Ray Tracing)\n\nGPU Ray Tracing with Raycore","title":"GPU Ray Tracing Tutorial"},{"category":"section","location":"index.html#Hardware-RT-Acceleration","page":"Home","text":"Use dedicated GPU ray tracing hardware (RT cores / Ray Accelerators) for transparent BVH acceleration via Vulkan.\n\n(Image: Hardware RT)\n\nHardware Ray Tracing with Lava","title":"Hardware RT Acceleration"},{"category":"section","location":"index.html#View-Factors-Analysis","page":"Home","text":"Calculate view factors, illumination, and centroids for radiosity and thermal analysis.\n\n(Image: View Factors)\n\nView Factors and More","title":"View Factors Analysis"},{"category":"section","location":"index.html#Overview","page":"Home","text":"","title":"Overview"},{"category":"section","location":"index.html#Private-Functions","page":"Home","text":"","title":"Private Functions"},{"category":"type","location":"index.html#Raycore.AbstractAccel","page":"Home","text":"AbstractAccel\n\nMutable acceleration structure for ray/geometry intersection queries.\n\nConcrete implementations:\n\nRaycore.TLAS — software BVH/TLAS, runs on any KernelAbstractions backend.\nLava.HWTLAS — hardware ray tracing via VK_KHR_ray_tracing_pipeline.\n\nMutation API\n\npush!(accel, mesh, transform): add geometry, return a TLASHandle.\ndelete!(accel, handle), update_transform!(accel, handle, transform), update_transforms!(accel, handle, transforms).\n\nLifecycle\n\nsync!(accel) — sole owner of accel.static_tlas. Rebuilds in place where possible; reassigns when a buffer had to grow. No-op on a clean accel. Does NOT block the CPU on a GPU fence; backend-internal timeline tracking handles the \"still in flight\" case.\nAdapt.adapt(backend, accel) === accel.static_tlas between sync!s. Consumers re-read accel.static_tlas (or call Adapt.adapt) per dispatch. Caching the adapted form across mutations is a contract violation.\n\nQuery\n\nclosest_hit(adapted, ray) -> (hit, tri, t, bary, instance_override)\nany_hit(adapted, ray) -> Bool\nworld_bound(accel), n_instances(accel), n_geometries(accel).\n\nFlush\n\nwait_for_gpu!(accel) — block CPU until all pending GPU work on this accel's queue has completed. Convenience for tear-down and benchmark isolation. Not part of the hot path.\n\n\n\n\n\n","title":"Raycore.AbstractAccel"},{"category":"type","location":"index.html#Raycore.BLAS","page":"Home","text":"BLAS{NodeArray, TriArray}\n\nBottom-Level Acceleration Structure - BVH over triangle geometry.\n\nType parameters allow CPU (Vector) or GPU (CuArray, ROCArray) storage.\n\n\n\n\n\n","title":"Raycore.BLAS"},{"category":"type","location":"index.html#Raycore.BLAS4","page":"Home","text":"BLAS4{NodeArray, TriArray}\n\nBottom-Level Acceleration Structure using BVH4 nodes.\n\n\n\n\n\n","title":"Raycore.BLAS4"},{"category":"type","location":"index.html#Raycore.BLASDescriptor","page":"Home","text":"BLASDescriptor\n\nLightweight descriptor for a BLAS in flat-array layout. Instead of storing device pointers to per-BLAS arrays (which fail on Metal when stored in GPU buffers), this stores offsets into concatenated flat arrays.\n\nFields:\n\nnodes_offset: 0-based offset into the flat allblasnodes array\nprimitives_offset: 0-based offset into the flat allblasprims array\nroot_aabb: Bounding box of the BLAS in local space\n\n\n\n\n\n","title":"Raycore.BLASDescriptor"},{"category":"type","location":"index.html#Raycore.BVHNode2","page":"Home","text":"BVHNode2\n\nCompact BVH node for two-child binary trees. Stores AABBs for both children inline (BVH2IL layout from RadeonRays).\n\nFields:\n\naabb0_min, aabb0_max: Child 0 bounding box (or vertex data for leaves)\naabb1_min, aabb1_max: Child 1 bounding box (or unused for leaves)\nchild0: Child 0 index (INVALID_NODE for leaves)\nchild1: Child 1 index (or primitive index for leaves)\nparent: Parent node index\n\n\n\n\n\n","title":"Raycore.BVHNode2"},{"category":"type","location":"index.html#Raycore.BVHNode4","page":"Home","text":"BVHNode4\n\n4-wide BVH node optimized for GPU traversal. Stores up to 4 children with their AABBs inline.\n\nMemory layout: 128 bytes (one cache line on most GPUs)\n\n4 child indices: 16 bytes\n4 AABBs: 96 bytes (24 bytes each)\nMetadata: 16 bytes\n\nLeaf nodes indicated by child_count == 0 and first primitive index in child0.\n\n\n\n\n\n","title":"Raycore.BVHNode4"},{"category":"type","location":"index.html#Raycore.CollisionResult","page":"Home","text":"CollisionResult{C, B}\n\nResult of collision detection, containing contact pairs and a reusable cache buffer.\n\nFields:\n\ncontacts: Vector of ContactPair (or similar) on the compute backend\nnum_contacts: Number of valid contacts\ncache: Internal buffer for reuse across frames via cache keyword\n\n\n\n\n\n","title":"Raycore.CollisionResult"},{"category":"type","location":"index.html#Raycore.ContactPair","page":"Home","text":"ContactPair\n\nA pair of contacting instances in a TLAS, identified by their 1-based instance indices.\n\n\n\n\n\n","title":"Raycore.ContactPair"},{"category":"type","location":"index.html#Raycore.FastClosure","page":"Home","text":"FastClosure{F, Args<:Tuple}\n\nA callable wrapper that validates a function and arguments are GPU-safe:\n\nFunction f has no captured variables (no Core.Box fields)\nArguments don't exceed compiler limits (tuple length, type depth)\n\nWhen called, appends stored args to the call: fc(x) == fc.f(x, fc.args...)\n\nThis is used internally by for_unrolled, map_unrolled, and reduce_unrolled.\n\n\n\n\n\n","title":"Raycore.FastClosure"},{"category":"type","location":"index.html#Raycore.InstanceDescriptor","page":"Home","text":"InstanceDescriptor\n\nDescribes an instance of a bottom-level BVH in world space.\n\nFields:\n\nblas_index: Index into BLAS array\ninstance_id: Scene-binding slot for this instance.  0 means \"inherit from the triangle's per-face metadata\"; any nonzero value is forwarded verbatim by closest_hit / any_hit as the 5th return value.  Hikari uses it as a medium_interface_idx override so N instances of one BLAS can have distinct materials / media / emission without duplicating the BLAS geometry.  Matches Vulkan's gl_InstanceCustomIndexEXT.\ntransform: Local-to-world transform (Vulkan row-major 3×4, Mat3x4f)\ninv_transform: World-to-local transform (Vulkan row-major 3×4, Mat3x4f)\nflags: Instance flags (reserved for future use)\n\n\n\n\n\n","title":"Raycore.InstanceDescriptor"},{"category":"type","location":"index.html#Raycore.MultiTypeSet","page":"Home","text":"MultiTypeSet(backend)\n\nMutable heterogeneous vector that builds GPU-ready structures on each push!. Takes a KernelAbstractions backend at construction.\n\nExample\n\nbackend = OpenCL.OpenCLBackend()\ndhv = MultiTypeSet(backend)\ntexture = rand(Float32, 20, 20)\nidx1 = push!(dhv, MatteMaterial(texture))\nidx2 = push!(dhv, GlassMaterial(1.5f0))\n\n# Access the GPU-ready StaticMultiTypeSet directly\ngpu_smv = dhv.static  # Always up-to-date, no adapt needed\n\nPush converts arrays to TextureRefs and stores texture data as GPU arrays. The static field is rebuilt on each push to stay up-to-date.\n\n\n\n\n\n","title":"Raycore.MultiTypeSet"},{"category":"type","location":"index.html#Raycore.RTHitResult","page":"Home","text":"RTHitResult\n\nRay hit output from hardware RT dispatch. 32 bytes.\n\ninstance_custom_index — value of gl_InstanceCustomIndexEXT at the hit. Under the current semantics this carries the InstanceDescriptor.instance_id (the interface-override slot).  0 means \"inherit from triangle metadata\".\ninstance_id — value of gl_InstanceID at the hit (0-based instance array position).  Used by the caller to look up per-instance data such as the BLAS triangle offset.\n\n\n\n\n\n","title":"Raycore.RTHitResult"},{"category":"type","location":"index.html#Raycore.RTRay","page":"Home","text":"RTRay\n\nRay input for hardware RT dispatch. 32 bytes, matches Vulkan/Metal layout.\n\n\n\n\n\n","title":"Raycore.RTRay"},{"category":"type","location":"index.html#Raycore.SetKey","page":"Home","text":"SetKey\n\nIndex into a heterogeneous vector, encoding both which type slot (1-based) and the index within that type's array.\n\ntype_idx: Which tuple slot (1-based), 0 = invalid/constant sentinel\nvec_idx: 1-based index within the vector at that slot\n\n\n\n\n\n","title":"Raycore.SetKey"},{"category":"type","location":"index.html#Raycore.StaticMultiTypeSet","page":"Home","text":"StaticMultiTypeSet{Data, Textures}\n\nImmutable heterogeneous collection with separate texture storage.\n\ndata: Tuple of GPU vectors for materials/objects\ntextures: Tuple of GPU vectors containing isbits device pointers\n\n\n\n\n\n","title":"Raycore.StaticMultiTypeSet"},{"category":"type","location":"index.html#Raycore.StaticTLAS","page":"Home","text":"StaticTLAS{NodeArray, InstArray, BLASNodeArray, BLASPrimArray, DescArray}\n\nImmutable Top-Level Acceleration Structure for GPU kernel traversal. This is what Adapt.adapt_structure returns from a TLAS.\n\nUses flat arrays with offset-based indexing instead of per-BLAS pointer arrays. This avoids the Metal issue where device pointers stored in GPU buffers cannot be reliably dereferenced by kernels.\n\nThe struct is immutable and contains only the arrays needed for ray traversal. No management state (dictionaries, free lists, etc.) - those stay on CPU in TLAS.\n\n\n\n\n\n","title":"Raycore.StaticTLAS"},{"category":"type","location":"index.html#Raycore.TLAS","page":"Home","text":"TLAS{Backend}\n\nMutable Top-Level Acceleration Structure with direct GPU arrays.\n\nGPU-first design: instances are appended directly to GPU array using efficient GPU append. CPU-side dictionary provides O(1) handle lookups.\n\nAdapted-form invariant (READ THIS)\n\nsync!(tlas) is the single owner of the GPU-adapted form. It rebuilds as efficiently as possible — in place via resize!/copyto! where the backing buffer can be reused, freshly allocated only when a buffer grew — and stores the result in tlas.static_tlas. sync! MAY reassign tlas.static_tlas = new_static_tlas when a buffer was reallocated.\n\nEvery consumer that hands an accel to a raytracing kernel MUST go through tlas.static_tlas or Adapt.adapt(backend, tlas) (which reads / refreshes tlas.static_tlas) per dispatch. Those are cheap; sync! did the heavy lifting. NEVER cache the StaticTLAS returned by adapt across mutations — after a reshape-driven reallocation the cached snapshot holds a stale device pointer.\n\nThe same contract applies to HWTLAS — see its docstring.\n\nType Parameters\n\nBackend: KernelAbstractions backend (CPU(), LavaBackend(), CUDABackend(), etc.)\n\nFields\n\nbackend: KernelAbstractions backend for kernels\nnodes: BVH nodes array (on backend, grown in place on sync! where possible)\ninstances: Instance descriptors array (GPU array, direct append)\nblas_array: BLAS objects array (GPU array with isbits pointers)\nroot_aabb: World-space bounding box\nhandle_to_range: Handle -> range in instances array (CPU-side)\ndeleted_handles: Handles deleted but not yet compacted (CPU-side)\nblas_storage: Per-BLAS backing arrays; keeps GPU buffers alive for isbits pointers\nstatic_tlas: GPU-adapted form, owned by sync!. Consumers read this, do  not cache it across mutations.\ndirty: Whether BVH topology needs rebuild\ntransforms_dirty: Whether instance transforms changed and the TLAS needs refit\nrevision: Monotonic counter bumped by every mutation that reshapes  GPU-visible arrays. Intended purely as a diagnostic signal — consumers that  go through tlas.static_tlas don't need to check it.\n\nUsage\n\ntlas = TLAS(CPU())\nh1 = push!(tlas, mesh)\nh2 = push!(tlas, mesh, transforms)\nupdate_transform!(tlas, h2, new_transform)\ndelete!(tlas, h1)\nsync!(tlas)                    # Rebuild / refresh tlas.static_tlas\nstatic = adapt(backend, tlas)  # Reads tlas.static_tlas — cheap, call per dispatch\n\n\n\n\n\n","title":"Raycore.TLAS"},{"category":"method","location":"index.html#Raycore.TLAS-Tuple{AbstractVector{<:GeometryBasics.Mesh}}","page":"Home","text":"TLAS(meshes::AbstractVector{<:GeometryBasics.Mesh}; backend=KA.CPU()) -> (TLAS, Vector{TLASHandle})\n\nCreate a mutable TLAS from a vector of GB.Mesh objects. Each mesh becomes a BLAS with a single instance at identity transform.\n\nReturns the mutable TLAS and a vector of TLASHandles for later reference.\n\nExamples\n\ntlas, handles = TLAS([floor_mesh, wall_mesh, sphere_mesh])\n\n\n\n\n\n","title":"Raycore.TLAS"},{"category":"method","location":"index.html#Raycore.TLAS-Tuple{Any}","page":"Home","text":"TLAS(backend) -> TLAS\n\nCreate an empty TLAS for the given backend. Use push! to add geometries/instances, then sync! to rebuild the BVH. Adapt.adapt_structure returns a StaticTLAS for kernel traversal.\n\nExample\n\ntlas = TLAS(OpenCLBackend())\nh1 = push!(tlas, geometry)\nh2 = push!(tlas, Instance(geometry, transforms))\nsync!(tlas)  # Rebuild BVH on backend\nstatic = adapt(backend, tlas)  # StaticTLAS with isbits pointers for kernels\n\n\n\n\n\n","title":"Raycore.TLAS"},{"category":"method","location":"index.html#Raycore.TLAS-Union{Tuple{P}, Tuple{AbstractVector{P}, Function}} where P","page":"Home","text":"TLAS(primitives::AbstractVector, metadata_fn::Function; backend=KA.CPU())\n\nUniversal TLAS constructor. Each primitive (GB.Mesh or AbstractGeometry) becomes a BLAS with a single instance.\n\nEach mesh is automatically treated as an instance at identity transform. Perfect for scenes where you just have different meshes and want automatic instancing.\n\nGPU-first: Specify backend to build all BLASes directly on GPU.\n\nExample:\n\ngeometries = [cat_mesh, floor, sphere]\ntlas = TLAS(geometries, (mesh_idx, tri_idx) -> UInt32(mesh_idx))\n\n# GPU-first:\ntlas = TLAS(geometries, metadata_fn; backend=OpenCLBackend())\n\n\n\n\n\n","title":"Raycore.TLAS"},{"category":"type","location":"index.html#Raycore.TLAS4","page":"Home","text":"TLAS4{NodeArray, InstArray, BLASArray}\n\nTop-Level Acceleration Structure using BVH4 nodes.\n\n\n\n\n\n","title":"Raycore.TLAS4"},{"category":"type","location":"index.html#Raycore.TLASHandle","page":"Home","text":"TLASHandle\n\nStable handle for referencing instances in a TLAS. Simple unique ID for O(1) lookup in handletorange dictionary.\n\n\n\n\n\n","title":"Raycore.TLASHandle"},{"category":"method","location":"index.html#Raycore.any_hit-Union{Tuple{R}, Tuple{StaticTLAS, R}} where R<:Raycore.AbstractRay","page":"Home","text":"any_hit(tlas::TLAS, ray::AbstractRay) -> (hit, primitive, distance, barycentric, instance_idx)\n\nTraverse two-level BVH to find ANY ray intersection (returns on first hit). Faster than closest_hit when only occlusion testing is needed.\n\nMatches HLSL TraceRays with ANY_HIT defined.\n\n\n\n\n\n","title":"Raycore.any_hit"},{"category":"method","location":"index.html#Raycore.any_hit4-Union{Tuple{R}, Tuple{BLAS4, R}} where R<:Raycore.AbstractRay","page":"Home","text":"any_hit4(blas::BLAS4, ray::AbstractRay) -> (hit, primitive, distance, barycentric)\n\nTraverse BVH4 to find any intersection (early exit).\n\n\n\n\n\n","title":"Raycore.any_hit4"},{"category":"method","location":"index.html#Raycore.build_blas-Union{Tuple{AbstractVector{T}}, Tuple{T}} where T<:Triangle","page":"Home","text":"build_blas(primitives) -> BLAS\n\nBuild a Bottom-Level Acceleration Structure using Linear BVH (LBVH).\n\nUses KernelAbstractions for automatic CPU/GPU execution based on input array type.\n\nAlgorithm:\n\nCompute scene AABB\nCalculate Morton codes in parallel (GPU kernel)\nSort primitives by Morton code\nBuild binary radix tree in parallel (GPU kernel)\nCompute AABBs bottom-up\n\nBased on Karras 2012 \"Maximizing Parallelism in the Construction of BVHs, Octrees, and k-d Trees\"\n\nArguments\n\nprimitives: Vector or GPU array of Triangle objects (array type determines backend)\n\nExample\n\n# CPU execution\nblas_cpu = build_blas(triangles)  # Vector{Triangle}\n\n# GPU execution (CUDA)\nusing CUDA\ngpu_triangles = CuArray(triangles)\nblas_gpu = build_blas(gpu_triangles)  # CuArray{Triangle}\n\n\n\n\n\n","title":"Raycore.build_blas"},{"category":"method","location":"index.html#Raycore.build_blas4-Union{Tuple{AbstractVector{T}}, Tuple{T}} where T<:Triangle","page":"Home","text":"build_blas4(primitives) -> BLAS4\n\nBuild a BLAS using BVH4 nodes for faster traversal.\n\nBuild standard LBVH (BVH2) using existing kernels\nCollapse BVH2 -> BVH4\n\n\n\n\n\n","title":"Raycore.build_blas4"},{"category":"method","location":"index.html#Raycore.build_tlas-Union{Tuple{B}, Tuple{AbstractVector{B}, AbstractVector{InstanceDescriptor}}} where B<:BLAS","page":"Home","text":"build_tlas(blas_array::AbstractVector{BLAS}, instances::AbstractVector{InstanceDescriptor}) -> StaticTLAS\n\nBuild a Top-Level Acceleration Structure over instances. Uses LBVH over transformed instance AABBs.\n\nReturns a StaticTLAS with flat BLAS arrays suitable for ray traversal. Uses KernelAbstractions for automatic CPU/GPU execution based on input array type.\n\n\n\n\n\n","title":"Raycore.build_tlas"},{"category":"method","location":"index.html#Raycore.build_topology_for_node-Tuple{Int32, AbstractVector{UInt32}, Int32}","page":"Home","text":"Build topology for one internal node. Regular Julia function for testability.\n\n\n\n\n\n","title":"Raycore.build_topology_for_node"},{"category":"method","location":"index.html#Raycore.build_triangle-NTuple{6, Any}","page":"Home","text":"build_triangle(vertices, normals, uvs, indices, face_idx, metadata)\n\nBuild a Triangle from decomposed mesh arrays at the given face index.\n\n\n\n\n\n","title":"Raycore.build_triangle"},{"category":"method","location":"index.html#Raycore.calculate_morton_code_for_prim-Tuple{Int64, AbstractVector{<:Triangle}, GeometryBasics.Point{3, Float32}, GeometryBasics.Vec{3, Float32}}","page":"Home","text":"Calculate Morton code for a single primitive. This is a regular Julia function, callable from CPU or GPU.\n\n\n\n\n\n","title":"Raycore.calculate_morton_code_for_prim"},{"category":"method","location":"index.html#Raycore.calculate_tlas_morton_code-Tuple{Int64, AbstractVector{InstanceDescriptor}, AbstractVector{<:BLAS}, GeometryBasics.Point{3, Float32}, GeometryBasics.Vec{3, Float32}}","page":"Home","text":"Calculate Morton code for a single instance centroid.\n\n\n\n\n\n","title":"Raycore.calculate_tlas_morton_code"},{"category":"method","location":"index.html#Raycore.closest_hit-Union{Tuple{R}, Tuple{StaticTLAS, R}} where R<:Raycore.AbstractRay","page":"Home","text":"closest_hit(tlas::TLAS, ray::AbstractRay) -> (hit, primitive, distance, barycentric, instance_idx)\n\nTraverse two-level BVH to find closest ray intersection.\n\ninstance_idx is the 1-based position in tlas.instances (or UInt32(0) on miss).  Dereferencing tlas.instances[instance_idx] yields the full InstanceDescriptor — from which the caller can read the transforms, the interface-override instance_id, or anything else.  This keeps a single source of truth (the TLAS instance array) rather than duplicating a pre-extracted sub-field.\n\nAlgorithm:\n\nTraverse TLAS to find candidate instances\nTransform ray to local space\nTraverse BLAS for geometry intersection\nTransform back to world space\nReturn closest hit across all instances\n\n\n\n\n\n","title":"Raycore.closest_hit"},{"category":"method","location":"index.html#Raycore.closest_hit4-Union{Tuple{R}, Tuple{BLAS4, R}} where R<:Raycore.AbstractRay","page":"Home","text":"closest_hit4(blas::BLAS4, ray::AbstractRay) -> (hit, primitive, distance, barycentric)\n\nTraverse BVH4 to find closest intersection.\n\n\n\n\n\n","title":"Raycore.closest_hit4"},{"category":"method","location":"index.html#Raycore.collide_instances-Tuple{TLAS}","page":"Home","text":"collide_instances(tlas::TLAS; cache=nothing) -> CollisionResult\n\nFind all pairs of instances whose world-space AABBs overlap.\n\nThis is a broad-phase test — it identifies which instances might be in contact based on their bounding boxes. For exact triangle-triangle contact, use collide.\n\nReturns a CollisionResult with ContactPairs (1-indexed instance IDs).\n\nExample\n\ntlas = TLAS(backend)\npush!(tlas, mesh_a, transform_a)\npush!(tlas, mesh_b, transform_b)\nsync!(tlas)\n\nresult = collide_instances(tlas)\nfor i in 1:result.num_contacts\n    pair = result.contacts[i]\n    println(\"Instance $(pair.instance_a) overlaps instance $(pair.instance_b)\")\nend\n\n# Reuse buffers for next frame:\nresult2 = collide_instances(tlas; cache=result.cache)\n\n\n\n\n\n","title":"Raycore.collide_instances"},{"category":"method","location":"index.html#Raycore.collide_instances_any-Tuple{TLAS, TLASHandle, TLASHandle}","page":"Home","text":"collide_instances_any(tlas::TLAS, handle_a::TLASHandle, handle_b::TLASHandle) -> Bool\n\nTest whether two specific instance groups overlap (broad-phase AABB test). Fast early-exit — returns true on first overlap found.\n\n\n\n\n\n","title":"Raycore.collide_instances_any"},{"category":"method","location":"index.html#Raycore.copyto_texture!-Union{Tuple{AT}, Tuple{MultiTypeSet, TextureRef{AT}, AbstractArray}} where AT","page":"Home","text":"copyto_texture!(dhv, ref, data)\n\nWrite data into the GPU texture addressed by ref.  Same-size is a plain copyto! (device pointer unchanged — no other state needs updating).  Size mismatch goes through Base.resize!(::LavaArray) which is capacity-aware: the VkBuffer is only re-allocated on genuine growth beyond current capacity, and the old buffer is retired via the deferred-free path (bq.deferred_frees gated on the batch timeline — safe w.r.t. in-flight GPU work without any CPU-side synchronize).\n\nIf the device pointer actually moved (pool-alloc returned a fresh buffer), the one affected slot of static.textures[AT_slot] is updated via a single scalar setindex! — no re-adapt of the whole table, no per-frame leak.\n\n\n\n\n\n","title":"Raycore.copyto_texture!"},{"category":"method","location":"index.html#Raycore.create_leaf_for_prim-Tuple{Int64, AbstractVector{<:Triangle}, BVHNode2, Int32}","page":"Home","text":"Create leaf node for one primitive. Regular Julia function.\n\n\n\n\n\n","title":"Raycore.create_leaf_for_prim"},{"category":"method","location":"index.html#Raycore.create_tlas_leaf_for_instance-Tuple{Int64, AbstractVector{<:Integer}, AbstractVector{InstanceDescriptor}, AbstractVector{<:BLAS}, UInt32}","page":"Home","text":"Create TLAS leaf node for one instance (stores world-space AABB, not triangle vertices).\n\n\n\n\n\n","title":"Raycore.create_tlas_leaf_for_instance"},{"category":"method","location":"index.html#Raycore.empty_triangle-Union{Tuple{Type{Triangle{TMeta}}}, Tuple{TMeta}} where TMeta","page":"Home","text":"empty_triangle(::Type{Triangle{TMeta}}) -> Triangle{TMeta}\n\nZero-initialized Triangle suitable as a no-hit sentinel. All vertex, normal, tangent, and uv components are 0; metadata is field-wise zero-constructed (works for any POD struct whose primitive fields have zero(T) defined).\n\nTakes the full Triangle type (not just the metadata type) so callers can write empty_triangle(eltype(triangles)) directly.\n\n\n\n\n\n","title":"Raycore.empty_triangle"},{"category":"method","location":"index.html#Raycore.for_unrolled-Union{Tuple{F}, Tuple{F, Tuple, Vararg{Any}}} where F","page":"Home","text":"for_unrolled(f, tuple, args...)\n\nIterate over tuple at compile-time, calling f(element, args...) for each element. No return value (use for side effects).\n\nThe function f must not capture any variables - pass all data as args instead.\n\nExample\n\nlights = (sun_light, point_light, spot_light)\ntotal = Ref(RGBSpectrum(0f0))\n\n# Bad - captures `total` and `ray`:\nfor light in lights\n    total[] += le(light, ray)  # Boxing on GPU!\nend\n\n# Good - pass as arguments:\nfor_unrolled(add_light!, lights, total, ray)\n# Where: add_light!(light, total, ray) = total[] += le(light, ray)\n\n\n\n\n\n","title":"Raycore.for_unrolled"},{"category":"method","location":"index.html#Raycore.for_unrolled-Union{Tuple{N}, Tuple{F}, Tuple{F, Val{N}, Vararg{Any}}} where {F, N}","page":"Home","text":"for_unrolled(f, ::Val{N}, args...)\n\nIterate from 1 to N at compile-time, calling f(i, args...) for each index.\n\n\n\n\n\n","title":"Raycore.for_unrolled"},{"category":"method","location":"index.html#Raycore.free!-Tuple{Any}","page":"Home","text":"free!(x)\n\nTrigger the registered finalizer on x to release GPU memory. Safe to call on any object — no-op if no finalizer is registered.\n\n\n\n\n\n","title":"Raycore.free!"},{"category":"method","location":"index.html#Raycore.free!-Tuple{MultiTypeSet}","page":"Home","text":"free!(set::MultiTypeSet)\n\nRelease GPU memory held by the MultiTypeSet — the shadow-owned texture arrays plus the static material/texture slot buffers.  Does not synchronize.\n\nPrecondition (caller's responsibility): the GPU must be idle for set.backend before this is called.  MultiTypeSet.texture_gpu_arrays is a shadow-ownership site: the only references from GPU work are raw BDAs in arg buffers, so nothing inside free! can prove it's safe to finalize — the caller establishes that, typically by calling sync! on the enclosing accel / scene (which synchronizes its backend) or by returning from a colorbuffer that completed with device_wait_idle.\n\n\n\n\n\n","title":"Raycore.free!"},{"category":"method","location":"index.html#Raycore.free!-Tuple{TLAS}","page":"Home","text":"free!(tlas::TLAS)\n\nRelease all GPU memory held by tlas.  Does not synchronize.\n\nPrecondition (caller's responsibility): the GPU must be idle for tlas.backend before this is called — either because the caller just returned from sync!(tlas) / Hikari.sync!(scene), from a colorbuffer that issued its own device_wait_idle, or because the caller has otherwise issued KA.synchronize(tlas.backend).\n\nCalling free! while dispatches are still in flight through a LavaArray / VkAccelerationStructureKHR BDA captured in an arg buffer is a use-after-free.\n\n\n\n\n\n","title":"Raycore.free!"},{"category":"method","location":"index.html#Raycore.get_child4-Tuple{BVHNode4, Int64}","page":"Home","text":"Get child index by position (0-3).\n\n\n\n\n\n","title":"Raycore.get_child4"},{"category":"method","location":"index.html#Raycore.get_child_aabb4-Tuple{BVHNode4, Int64}","page":"Home","text":"Get child AABB by position (1-4).\n\n\n\n\n\n","title":"Raycore.get_child_aabb4"},{"category":"function","location":"index.html#Raycore.get_instance","page":"Home","text":"get_instance(tlas::TLAS, handle::TLASHandle) -> InstanceDescriptor\nget_instance(tlas::TLAS, handle::TLASHandle, instance_idx::Integer) -> InstanceDescriptor\n\nRetrieve the InstanceDescriptor for a handle. If the handle has multiple instances (created with multiple transforms), use instance_idx to specify which one (1-based).\n\nNote: Reads from GPU array, may involve a device-to-host copy.\n\n\n\n\n\n","title":"Raycore.get_instance"},{"category":"method","location":"index.html#Raycore.get_instances-Tuple{TLAS, TLASHandle}","page":"Home","text":"get_instances(tlas::TLAS, handle::TLASHandle) -> Vector{InstanceDescriptor}\n\nRetrieve all InstanceDescriptors for a handle (for handles with multiple transforms).\n\nNote: Reads from GPU array, involves a device-to-host copy.\n\n\n\n\n\n","title":"Raycore.get_instances"},{"category":"method","location":"index.html#Raycore.getindex_unrolled-Union{Tuple{F}, Tuple{F, Tuple, Int32, Vararg{Any}}} where F","page":"Home","text":"getindex_unrolled(f, tuple, idx::Int32, args...) -> result\n\nSelect element at runtime index idx from tuple and apply f(element, args...). Uses unrolled if-branches for GPU compatibility - no dynamic dispatch.\n\nThe index is 1-based. If idx is out of bounds, returns f(tuple[1], args...) as fallback.\n\nExample\n\nlights = (sun_light, point_light, env_light)\nlight_idx = Int32(2)\n\n# Sample from the selected light\nsample = getindex_unrolled(sample_light, lights, light_idx, point, lambda, u)\n# Equivalent to: sample_light(point_light, point, lambda, u)\n\n\n\n\n\n","title":"Raycore.getindex_unrolled"},{"category":"function","location":"index.html#Raycore.instance_buffer","page":"Home","text":"instance_buffer(tlas, handle::TLASHandle)\n\nReturn the underlying GPU instance buffer (a Lava.LavaArray{LavaInstanceRecord, 1}) that the named batch is using. The caller can write into this buffer (e.g., via a compute kernel) and then call refit_tlas!(tlas) to commit the changes.\n\nErrors loudly if the handle does not refer to an instance batch (e.g., it refers to a per-mesh push! instance, which has no GPU instance buffer).\n\n\n\n\n\n","title":"Raycore.instance_buffer"},{"category":"method","location":"index.html#Raycore.is_degenerate_face-Tuple{Any, Any, Any}","page":"Home","text":"is_degenerate_face(vertices, indices, face_idx)\n\nCheck if a triangle face is degenerate (zero area) without constructing a full Triangle.\n\n\n\n\n\n","title":"Raycore.is_degenerate_face"},{"category":"method","location":"index.html#Raycore.is_interior4-Tuple{BVHNode4}","page":"Home","text":"Check if node is interior.\n\n\n\n\n\n","title":"Raycore.is_interior4"},{"category":"method","location":"index.html#Raycore.is_leaf4-Tuple{BVHNode4}","page":"Home","text":"Check if node is a leaf.\n\n\n\n\n\n","title":"Raycore.is_leaf4"},{"category":"method","location":"index.html#Raycore.is_valid-Tuple{TLAS, TLASHandle}","page":"Home","text":"is_valid(tlas::TLAS, handle::TLASHandle) -> Bool\n\nCheck if a handle is still valid (not deleted). O(1) operation.\n\n\n\n\n\n","title":"Raycore.is_valid"},{"category":"method","location":"index.html#Raycore.map_unrolled-Union{Tuple{F}, Tuple{F, Tuple, Vararg{Any}}} where F","page":"Home","text":"map_unrolled(f, tuple, args...) -> Tuple\n\nTransform each element of tuple at compile-time, returning a new tuple. Calls f(element, args...) for each element.\n\nExample\n\nlights = (sun_light, point_light)\ncontributions = map_unrolled(compute_light, lights, hit_point, normal)\n# Returns: (compute_light(sun_light, hit_point, normal),\n#           compute_light(point_light, hit_point, normal))\n\n\n\n\n\n","title":"Raycore.map_unrolled"},{"category":"method","location":"index.html#Raycore.n_geometries-Tuple{TLAS}","page":"Home","text":"n_geometries(tlas::TraversableTLAS)\n\nReturn number of unique BLAS geometries in the TLAS.\n\n\n\n\n\n","title":"Raycore.n_geometries"},{"category":"method","location":"index.html#Raycore.n_instances-Tuple{StaticTLAS}","page":"Home","text":"n_instances(tlas::TraversableTLAS)\n\nReturn total number of live instance descriptors in the TLAS.\n\nFor a TLAS, instances delete!d but not yet compacted by sync! are excluded; the count tracks what the next sync! will publish, not the backing buffer length. StaticTLAS has no pending state, so it returns length(tlas.instances) directly.\n\n\n\n\n\n","title":"Raycore.n_instances"},{"category":"method","location":"index.html#Raycore.n_instances-Tuple{TLAS, TLASHandle}","page":"Home","text":"n_instances(tlas::TLAS, handle::TLASHandle) -> Int\n\nGet the number of instances referenced by a handle.\n\n\n\n\n\n","title":"Raycore.n_instances"},{"category":"method","location":"index.html#Raycore.n_total_instances-Tuple{TLAS}","page":"Home","text":"n_total_instances(tlas::TLAS) -> Int\n\nGet the total number of active instances in the TLAS.\n\n\n\n\n\n","title":"Raycore.n_total_instances"},{"category":"method","location":"index.html#Raycore.reduce_unrolled-Union{Tuple{F}, Tuple{F, Tuple, Any, Vararg{Any}}} where F","page":"Home","text":"reduce_unrolled(f, tuple, init, args...) -> result\n\nReduce tuple at compile-time using f(accumulator, element, args...).\n\nExample\n\nlights = (sun_light, point_light, env_light)\n\n# Compute total light contribution\ntotal = reduce_unrolled(add_light_contribution, lights, RGBSpectrum(0f0), ray, hit_point)\n# Where: add_light_contribution(acc, light, ray, hp) = acc + compute_li(light, ray, hp)\n\n\n\n\n\n","title":"Raycore.reduce_unrolled"},{"category":"method","location":"index.html#Raycore.refit_node_aabb-Tuple{Int32, AbstractVector{BVHNode2}, Int32}","page":"Home","text":"Refit AABB for one internal node from its children.\n\n\n\n\n\n","title":"Raycore.refit_node_aabb"},{"category":"method","location":"index.html#Raycore.reflect-Tuple{GeometryBasics.Vec{3, Float32}, GeometryBasics.Vec{3, Float32}}","page":"Home","text":"Reflect wo about n.\n\n\n\n\n\n","title":"Raycore.reflect"},{"category":"method","location":"index.html#Raycore.set_parents_for_node-Tuple{Int32, AbstractVector{BVHNode2}}","page":"Home","text":"Set parent pointers for one node's children. Regular Julia function.\n\n\n\n\n\n","title":"Raycore.set_parents_for_node"},{"category":"method","location":"index.html#Raycore.similar_soa-Union{Tuple{T}, Tuple{Any, Type{T}, Any}} where T","page":"Home","text":"similar_soa(template_array, T::Type, num_elements) -> NamedTuple\n\nCreate a Structure of Arrays (SoA) layout for type T with num_elements entries. Uses template_array to determine the array type (Array, ROCArray, etc.).\n\n\n\n\n\n","title":"Raycore.similar_soa"},{"category":"method","location":"index.html#Raycore.sum_unrolled-Union{Tuple{F}, Tuple{F, Tuple, Vararg{Any}}} where F","page":"Home","text":"sum_unrolled(f, tuple, args...) -> result\n\nSum f(element, args...) over all elements of tuple.\n\nExample\n\nlights = (sun_light, point_light)\ntotal = sum_unrolled(le, lights, ray)\n# Computes: le(sun_light, ray) + le(point_light, ray)\n\n\n\n\n\n","title":"Raycore.sum_unrolled"},{"category":"method","location":"index.html#Raycore.sync!-Tuple{TLAS}","page":"Home","text":"sync!(tlas::TLAS) -> TLAS\n\nRebuild the BVH structure if dirty, then wait for the GPU to finish all work currently queued on tlas.backend (via KA.synchronize). No-op if already up-to-date AND no work is pending.\n\nsync! is the single owner of tlas.static_tlas. It rebuilds in place (resize!/copyto! on the same backing buffer) wherever possible so that a StaticTLAS returned by an earlier Adapt.adapt(backend, tlas) still sees the new geometry, and reallocates + reassigns tlas.static_tlas when a buffer needed to grow.\n\nAfter sync!(tlas) returns:\n\nThe TLAS reflects all prior push!/delete! calls.\ntlas.static_tlas is the fresh adapted form.\nThe GPU is idle for tlas.backend.\nAny resource that is no longer reachable through the (new) accel is safe to release synchronously: its VkAccelerationStructureKHR / BDA captures in in-flight work have drained.\n\nInvariants for callers:\n\nupdate! / push! / delete! on the TLAS do NOT wait and do NOT perform cleanup; they mark state dirty and return immediately. Call sync! to establish a safe boundary before freeing transitively- owned resources.\nConsumers of the adapted form read tlas.static_tlas (or call Adapt.adapt(backend, tlas)) per dispatch. They MUST NOT cache the returned StaticTLAS across mutations — after a reshape-driven reassign the cached snapshot holds a stale device pointer.\n\n\n\n\n\n","title":"Raycore.sync!"},{"category":"method","location":"index.html#Raycore.update!-Tuple{MultiTypeSet, SetKey, Any}","page":"Home","text":"update!(dhv::MultiTypeSet, key::SetKey, new_item)\n\nUpdate an existing item in the set.  The new item is walked against the stored form via update_item: existing TextureRef slots are reused (the new array data is copied into the existing GPU buffer, reallocating on size mismatch), const-Texture fields are unwrapped to their scalar values, and other fields fall through as plain value replacement.\n\nThere is deliberately no maybe_convert_field/store_texture call on this path — that would allocate a new GPU slot per update and leak hundreds of MB per frame for plots with per-vertex color textures.\n\n\n\n\n\n","title":"Raycore.update!"},{"category":"method","location":"index.html#Raycore.update!-Tuple{TLAS, TLASHandle, Any}","page":"Home","text":"update!(tlas::TLAS, handle::TLASHandle, new_geometry)\n\nReplace the geometry (BLAS) for a handle. All instances sharing this BLAS get updated.\n\n\n\n\n\n","title":"Raycore.update!"},{"category":"method","location":"index.html#Raycore.update_item-Union{Tuple{AT}, Tuple{MultiTypeSet, TextureRef{AT}, AbstractArray}} where AT","page":"Home","text":"update_item(dhv::MultiTypeSet, old, new)\n\nCompute the updated representation of old after applying new's data. Reuses existing TextureRef slots (copying new's arrays into them rather than allocating fresh GPU buffers).  Extended by backend / material packages (e.g. Hikari) with overloads for their wrapper types — notably Texture (unwraps const, routes array data to copyto_texture!) and VertexColorTexture.\n\n\n\n\n\n","title":"Raycore.update_item"},{"category":"method","location":"index.html#Raycore.update_particle_materials_kernel!-Tuple{Any}","page":"Home","text":"GPU kernel: Batch update materials based on particle velocities.\n\nUpdates material colors using a heat-map based on velocity magnitude. Also updates metallic/roughness with per-particle noise variation.\n\n\n\n\n\n","title":"Raycore.update_particle_materials_kernel!"},{"category":"method","location":"index.html#Raycore.update_tlas_leaf_aabbs_kernel!-Tuple{Any}","page":"Home","text":"GPU kernel: Update TLAS leaf node AABBs from instance transforms.\n\nAfter transforms are updated, this kernel recomputes world-space AABBs for all leaf nodes. Must be called before refittlasaabbs_kernel!.\n\nNOTE: Leaf nodes are Morton-sorted, so we must use the stored instance index (child1) to look up the correct instance.\n\n\n\n\n\n","title":"Raycore.update_tlas_leaf_aabbs_kernel!"},{"category":"method","location":"index.html#Raycore.update_transform!-Tuple{TLAS, TLASHandle, StaticArraysCore.SMatrix{4, 3, Float32, 12}}","page":"Home","text":"update_transform!(tlas::TLAS, handle::TLASHandle, transform)\n\nUpdate the transform of a single-instance handle directly on GPU. For handles with multiple instances, use update_transforms!.\n\ntransform may be a Mat4f (homogeneous 4×4) or the canonical Vulkan row-major 3×4 (Mat3x4f); the Mat4f form is converted internally via mat4_to_mat3x4. After calling this, use refit_tlas! to update the BVH AABBs.\n\n\n\n\n\n","title":"Raycore.update_transform!"},{"category":"method","location":"index.html#Raycore.update_transforms!-Tuple{TLAS, TLASHandle, AbstractVector{StaticArraysCore.SMatrix{4, 3, Float32, 12}}}","page":"Home","text":"update_transforms!(tlas::TLAS, handle::TLASHandle, transforms)\n\nUpdate all instances' transforms in a group directly on GPU. Length must match the number of instances in the handle.\n\nTransforms may be Mat4f or the canonical Vulkan row-major 3×4 (Mat3x4f); Mat4f arrays are converted element-wise via mat4_to_mat3x4. The array can be CPU or GPU — it'll be adapted to the TLAS backend. After calling this, use refit_tlas! to update the BVH AABBs.\n\n\n\n\n\n","title":"Raycore.update_transforms!"},{"category":"method","location":"index.html#Raycore.wait_for_gpu!-Tuple{AbstractAccel}","page":"Home","text":"wait_for_gpu!(accel::AbstractAccel)\n\nBlock the CPU until the GPU has completed all prior work that could be reading accel or its adapted form. Default implementation calls KA.synchronize on accel.backend. Concrete types that carry their own queue (e.g. Lava.HWTLAS) override this to wait on the specific timeline.\n\nConvenience only. The per-dispatch hot path does NOT call this; see sync!.\n\n\n\n\n\n","title":"Raycore.wait_for_gpu!"},{"category":"method","location":"index.html#Raycore.with_index-Union{Tuple{Textures}, Tuple{Data}, Tuple{F}, Tuple{F, StaticMultiTypeSet{Data, Textures}, SetKey, Vararg{Any}}} where {F, Data<:Tuple, Textures}","page":"Home","text":"with_index(f, smv::StaticMultiTypeSet, idx::SetKey, args...)\n\nExecute function f with the element at index idx, passing additional args. The function is called as f(element, args...) where element has a concrete type.\n\nUses a single if-elseif-else chain for SPIR-V structured control flow compatibility. The function f must not capture variables - pass all data as args.\n\n\n\n\n\n","title":"Raycore.with_index"},{"category":"method","location":"index.html#Raycore.world_bound-Tuple{BLAS}","page":"Home","text":"Get world-space AABB of a BLAS.\n\n\n\n\n\n","title":"Raycore.world_bound"},{"category":"method","location":"index.html#Raycore.world_bound-Tuple{TraversableTLAS}","page":"Home","text":"Get world-space AABB of a TLAS.\n\n\n\n\n\n","title":"Raycore.world_bound"},{"category":"macro","location":"index.html#Raycore.@get-Tuple{Any}","page":"Home","text":"@get field1, field2, ... = soa[idx]\n\nMacro to extract multiple fields from a Structure of Arrays (SoA) at index idx.\n\nExample\n\nray_queue = (ray=[r1, r2, r3], pixel_x=[1, 2, 3], pixel_y=[4, 5, 6])\n@get ray, pixel_x, pixel_y = ray_queue[2]\n# Expands to:\n# ray = ray_queue.ray[2]\n# pixel_x = ray_queue.pixel_x[2]\n# pixel_y = ray_queue.pixel_y[2]\n\n\n\n\n\n","title":"Raycore.@get"},{"category":"macro","location":"index.html#Raycore.@set-Tuple{Any}","page":"Home","text":"@set soa[idx] = (field1=val1, field2=val2, ...)\n\nMacro to set multiple fields in a Structure of Arrays (SoA) at index idx. Expects named tuple syntax on the right side.\n\nExample\n\nray_queue = (ray=Vector{Ray}(undef, 10), pixel_x=zeros(Int32, 10))\n@set ray_queue[1] = (ray=my_ray, pixel_x=Int32(5))\n# Expands to:\n# ray_queue.ray[1] = my_ray\n# ray_queue.pixel_x[1] = Int32(5)\n\n\n\n\n\n","title":"Raycore.@set"},{"category":"constant","location":"index.html#Raycore.TOP_LEVEL_SENTINEL","page":"Home","text":"Sentinel value to mark top-level to bottom-level transitions.\n\n\n\n\n\n","title":"Raycore.TOP_LEVEL_SENTINEL"},{"category":"type","location":"index.html#Raycore.BLASArrays","page":"Home","text":"BLASArrays\n\nPer-BLAS backing GPU arrays.  Field ownership transitively keeps the nodes / primitives buffers alive while the TLAS holds them, so the isbits device pointers stored in blas_array (and the flat arrays used by StaticTLAS) remain valid.\n\nprimitives is left at the bare AbstractVector bound rather than AbstractVector{<:Triangle} because differently-parameterized Triangle{TMetadata} subtypes need to coexist across BLASes; the tighter bound forces a UnionAll that doesn't help dispatch.\n\n\n\n\n\n","title":"Raycore.BLASArrays"},{"category":"type","location":"index.html#Raycore.BVH4Leaf","page":"Home","text":"BVH4Leaf\n\nLeaf node that stores triangle vertices directly (like BVH2IL format). For BVH4, we keep triangles separate and reference by index.\n\n\n\n\n\n","title":"Raycore.BVH4Leaf"},{"category":"type","location":"index.html#Raycore.CollapseTask","page":"Home","text":"CollapseTask\n\nWork item for the BVH2 -> BVH4 collapse pass.\n\n\n\n\n\n","title":"Raycore.CollapseTask"},{"category":"method","location":"index.html#Adapt.adapt_structure-Tuple{Any, StaticTLAS}","page":"Home","text":"Adapt.adapt_structure(to, tlas::StaticTLAS) -> StaticTLAS\n\nAdapt StaticTLAS arrays. If already isbits, returns as-is. Otherwise adapts each array (CLArray → CLDeviceVector).\n\nNote: StaticTLAS should come from adapting a mutable TLAS, where BLASes already have isbits device pointers. Use TLAS(items) to create a mutable TLAS that properly manages GPU array lifetimes.\n\n\n\n\n\n","title":"Adapt.adapt_structure"},{"category":"method","location":"index.html#Adapt.adapt_structure-Tuple{Any, TLAS}","page":"Home","text":"Adapt.adapt_structure(to, tlas::TLAS) -> StaticTLAS\n\nReturn tlas.static_tlas after a sync! to make sure it reflects any pending mutation. sync! is the single owner of that field; this function just reads it. On a clean TLAS, sync! is a true no-op — no GPU synchronize, no allocations — so this is cheap to call per dispatch. Do call it per dispatch, and do NOT cache the return.\n\ntlas.static_tlas is in kernel-ready isbits form on tlas.backend. The to argument is checked: passing a KA.Backend other than tlas.backend errors loudly. Cross-backend conversion is not supported — build the TLAS on the same backend you intend to dispatch kernels against.\n\n\n\n\n\n","title":"Adapt.adapt_structure"},{"category":"method","location":"index.html#Base.delete!-Tuple{TLAS, TLASHandle}","page":"Home","text":"delete!(tlas::TLAS, handle::TLASHandle) -> Bool\n\nRemove all instances referenced by the handle. Returns true if successful. The handle becomes invalid after deletion.\n\nNote: The instances array is compacted during sync!, not immediately.\n\n\n\n\n\n","title":"Base.delete!"},{"category":"method","location":"index.html#Base.eltype-Tuple{TLAS}","page":"Home","text":"Base.eltype(tlas::TraversableTLAS)\n\nGet the element type of primitives stored in the TLAS.  Returns the element type of the first BLAS's primitives; defaults to Triangle{UInt32} when the TLAS has no BLASes yet.\n\n\n\n\n\n","title":"Base.eltype"},{"category":"function","location":"index.html#Base.push!","page":"Home","text":"push!(tlas::TLAS, mesh::GeometryBasics.Mesh, transform::Mat4f=Mat4f(I);\n      instance_id::UInt32=UInt32(0)) -> TLASHandle\n\nAdd a GeometryBasics.Mesh to the TLAS. Per-face metadata is read from the mesh's face_meta attribute (if present). If no face_meta attribute exists, each triangle gets UInt32(face_idx) as metadata.\n\ninstance_id is forwarded to the InstanceDescriptor.  It defaults to 0 (inherit from triangle metadata); pass a nonzero value to override the per-triangle interface — see InstanceDescriptor for semantics.\n\nReturns a stable handle for later reference.\n\n\n\n\n\n","title":"Base.push!"},{"category":"method","location":"index.html#Base.push!-Tuple{TLAS, GeometryBasics.Mesh, AbstractVector{StaticArraysCore.SMatrix{4, 4, Float32, 16}}}","page":"Home","text":"push!(tlas::TLAS, mesh::GeometryBasics.Mesh, transforms::AbstractVector{Mat4f};\n      instance_ids::Union{Nothing, AbstractVector{UInt32}}=nothing) -> TLASHandle\n\nAdd a GeometryBasics.Mesh to the TLAS with multiple transforms (instancing). Builds BLAS once, creates length(transforms) InstanceDescriptors.\n\ninstance_ids (if given) must match length(transforms) and supplies the per-instance interface override.  When nothing, every instance gets 0 (inherit from triangle metadata).\n\nReturns a stable handle for later reference.\n\n\n\n\n\n","title":"Base.push!"},{"category":"method","location":"index.html#Raycore._zero_struct-Union{Tuple{Type{T}}, Tuple{T}} where T","page":"Home","text":"_zero_struct(::Type{T}) -> T\n\nField-wise zero-initialise a POD struct T.  Recursive over fieldtype(T, i) so nested structs (e.g. Triangle{TriangleMeta} where TriangleMeta has UInt32 fields) work without requiring zero(T) to be defined on the outer type.  Falls back to zero(T) for primitive leaves.\n\n\n\n\n\n","title":"Raycore._zero_struct"},{"category":"method","location":"index.html#Raycore.aabb_overlaps-NTuple{4, GeometryBasics.Point{3, Float32}}","page":"Home","text":"Test if two AABBs overlap.\n\n\n\n\n\n","title":"Raycore.aabb_overlaps"},{"category":"method","location":"index.html#Raycore.allocate_empty_blas_array-Tuple{Any}","page":"Home","text":"Helper to create initial empty BLAS array placeholder.\n\n\n\n\n\n","title":"Raycore.allocate_empty_blas_array"},{"category":"method","location":"index.html#Raycore.append_blas!-Tuple{Any, Any, Any}","page":"Home","text":"Append a single isbits BLAS to blasarray using GPU-friendly append!. Returns the (possibly new) blasarray.\n\n\n\n\n\n","title":"Raycore.append_blas!"},{"category":"method","location":"index.html#Raycore.append_instances_with_handle!-Tuple{TLAS, AbstractVector{InstanceDescriptor}}","page":"Home","text":"Internal: append the given instance descriptors to tlas.instances, register a handle for the appended range, and return it.\n\n\n\n\n\n","title":"Raycore.append_instances_with_handle!"},{"category":"method","location":"index.html#Raycore.build_and_append_blas!-Tuple{TLAS, GeometryBasics.Mesh}","page":"Home","text":"Internal: decompose a GB.Mesh, build a BLAS, append it to the TLAS, and return the new BLAS's 1-based index.  Shared by every push! variant.\n\n\n\n\n\n","title":"Raycore.build_and_append_blas!"},{"category":"method","location":"index.html#Raycore.build_flat_blas_arrays!-Tuple{TLAS}","page":"Home","text":"build_flat_blas_arrays!(tlas::TLAS)\n\nBuild concatenated flat arrays from individual BLAS GPU arrays and store them in tlas._flat_blas_nodes, tlas._flat_blas_prims, tlas._flat_blas_descs.\n\nThis avoids storing device pointers in GPU buffers (which fails on Metal). Instead, traversal kernels use BLASDescriptor offsets to index into the flat arrays.\n\nThe flat arrays are MtlVector/CuVector etc., kept alive by the TLAS. During adapt, they are converted to isbits device pointers for kernels.\n\n\n\n\n\n","title":"Raycore.build_flat_blas_arrays!"},{"category":"method","location":"index.html#Raycore.build_tlas_topology-Tuple{Any, Any, Any}","page":"Home","text":"build_tlas_topology(blas_array, instances, backend) -> (nodes, root_aabb)\n\nInternal: Build TLAS BVH topology (Morton codes, sorting, tree construction, refit). Returns (nodes, rootaabb). Only accesses blasarray for root_aabb (inline data).\n\ninstances must already be on the backend.\n\n\n\n\n\n","title":"Raycore.build_tlas_topology"},{"category":"method","location":"index.html#Raycore.build_tlas_topology_for_node-Tuple{Int32, AbstractVector{UInt32}, Int32}","page":"Home","text":"Build topology for one TLAS internal node (same algorithm as BLAS).\n\n\n\n\n\n","title":"Raycore.build_tlas_topology_for_node"},{"category":"method","location":"index.html#Raycore.calculate_morton_codes_kernel!-Tuple{Any}","page":"Home","text":"GPU kernel: Parallel dispatch for Morton code calculation.\n\n\n\n\n\n","title":"Raycore.calculate_morton_codes_kernel!"},{"category":"method","location":"index.html#Raycore.calculate_tlas_morton_codes_kernel!-Tuple{Any}","page":"Home","text":"GPU kernel: Calculate Morton codes for TLAS instances.\n\n\n\n\n\n","title":"Raycore.calculate_tlas_morton_codes_kernel!"},{"category":"method","location":"index.html#Raycore.check_args_limits-Union{Tuple{Type{Args}}, Tuple{Args}} where Args<:Tuple","page":"Home","text":"check_args_limits(::Type{Args}) where Args\n\nCompile-time check that argument types don't exceed compiler limits.\n\n\n\n\n\n","title":"Raycore.check_args_limits"},{"category":"method","location":"index.html#Raycore.check_no_capture-Union{Tuple{Type{F}}, Tuple{F}} where F","page":"Home","text":"check_no_capture(::Type{F}) where F\n\nCompile-time check that function type F has no captured variables. Any closure field indicates a captured variable which should be passed as an argument instead. Core.Box fields are especially problematic (heap-allocated, type-unstable).\n\n\n\n\n\n","title":"Raycore.check_no_capture"},{"category":"method","location":"index.html#Raycore.clz32-Tuple{UInt32}","page":"Home","text":"Count leading zeros (clz) for 32-bit integer.\n\n\n\n\n\n","title":"Raycore.clz32"},{"category":"method","location":"index.html#Raycore.collapse_bvh2_to_bvh4-Tuple{AbstractVector{BVHNode2}, AbstractVector{<:Triangle}, Int32}","page":"Home","text":"Collapse a BVH2 into a BVH4.\n\nThis is a sequential CPU implementation for simplicity. A GPU version would use work queues similar to HIPRT.\n\nThe key insight is that we need to:\n\nCollect up to 4 subtrees at each BVH4 interior node\nFor leaf subtrees, create BVH4 leaf nodes pointing to primitives\nFor interior subtrees, recursively process them\nFix up child pointers to point to BVH4 indices (not BVH2 indices)\n\n\n\n\n\n","title":"Raycore.collapse_bvh2_to_bvh4"},{"category":"method","location":"index.html#Raycore.collide_instances_kernel!-Tuple{Any}","page":"Home","text":"collide_instances_kernel!\n\nFor each TLAS leaf (instance), traverse the TLAS tree to find overlapping instances. Two-pass: when contacts is nothing, only counts. When not nothing, writes pairs.\n\nUses stack-based depth-first traversal, same pattern as closest_hit but testing AABB-AABB overlap instead of ray-AABB intersection.\n\n\n\n\n\n","title":"Raycore.collide_instances_kernel!"},{"category":"method","location":"index.html#Raycore.compact_instances!-Tuple{TLAS}","page":"Home","text":"Internal: Compact instances array by removing deleted handles, and compact BLASes.\n\n\n\n\n\n","title":"Raycore.compact_instances!"},{"category":"method","location":"index.html#Raycore.compute_instance_aabbs_kernel!-Tuple{Any}","page":"Home","text":"GPU kernel: Compute world AABBs for all instances, storing min/max points separately.\n\n\n\n\n\n","title":"Raycore.compute_instance_aabbs_kernel!"},{"category":"method","location":"index.html#Raycore.compute_instance_world_aabb-Tuple{InstanceDescriptor, AbstractVector{<:BLAS}}","page":"Home","text":"Compute world AABB for a single instance by transforming local AABB corners. Returns (minpoint, maxpoint) as two Point3f values.\n\n\n\n\n\n","title":"Raycore.compute_instance_world_aabb"},{"category":"method","location":"index.html#Raycore.cos_θ-Tuple{GeometryBasics.Vec{3, Float32}}","page":"Home","text":"The shading coordinate system gives a frame for expressing directions in spherical coordinates (θ, ϕ). The angle θ is measured from the given direction to the z-axis and ϕ is the angle formed with the x-axis after projection of the direction onto xy-plane.\n\nSince normal is (0, 0, 1) → cos_θ = n · w = (0, 0, 1) ⋅ w = w.z.\n\n\n\n\n\n","title":"Raycore.cos_θ"},{"category":"method","location":"index.html#Raycore.create_leaf_nodes_kernel!-Tuple{Any}","page":"Home","text":"GPU kernel: Parallel leaf node creation.\n\n\n\n\n\n","title":"Raycore.create_leaf_nodes_kernel!"},{"category":"method","location":"index.html#Raycore.create_tlas_leaf_nodes_kernel!-Tuple{Any}","page":"Home","text":"GPU kernel: Create TLAS leaf nodes.\n\n\n\n\n\n","title":"Raycore.create_tlas_leaf_nodes_kernel!"},{"category":"method","location":"index.html#Raycore.delta-Tuple{Int32, Int32, AbstractVector{UInt32}, Int32}","page":"Home","text":"Compute longest common prefix (LCP) of Morton codes. Uses index fallback when codes are identical.\n\n\n\n\n\n","title":"Raycore.delta"},{"category":"method","location":"index.html#Raycore.emit_topology_kernel!-Tuple{Any}","page":"Home","text":"GPU kernel: Parallel topology emission.\n\n\n\n\n\n","title":"Raycore.emit_topology_kernel!"},{"category":"method","location":"index.html#Raycore.empty_bvh4_node-Tuple{}","page":"Home","text":"Create an empty/invalid BVH4 node.\n\n\n\n\n\n","title":"Raycore.empty_bvh4_node"},{"category":"method","location":"index.html#Raycore.expand_bits-Tuple{UInt32}","page":"Home","text":"3-dilate bits for Morton code (spreads bits by factor of 3).\n\n\n\n\n\n","title":"Raycore.expand_bits"},{"category":"method","location":"index.html#Raycore.face_forward-Tuple{Any, Any}","page":"Home","text":"Flip normal n so that it lies in the same hemisphere as v.\n\n\n\n\n\n","title":"Raycore.face_forward"},{"category":"method","location":"index.html#Raycore.fast_intersect_bbox-Tuple{GeometryBasics.Point{3, Float32}, GeometryBasics.Vec{3, Float32}, Bounds3, Float32, Float32}","page":"Home","text":"fast_intersect_bbox(ray_o, ray_inv_d, bbox, t_min, t_max) -> (entry_t, exit_t)\n\nFast ray-AABB intersection using slab method. Returns parametric distances to entry and exit points. Matches HLSL fastintersectbbox.\n\n\n\n\n\n","title":"Raycore.fast_intersect_bbox"},{"category":"method","location":"index.html#Raycore.fast_intersect_bbox4-Tuple{GeometryBasics.Point{3, Float32}, GeometryBasics.Vec{3, Float32}, BVHNode4, Int64, Float32, Float32}","page":"Home","text":"fast_intersect_bbox4(ray_o, ray_inv_d, node, child_idx, t_min, t_max) -> (hit, t_entry)\n\nTest ray against one child AABB of a BVH4 node.\n\n\n\n\n\n","title":"Raycore.fast_intersect_bbox4"},{"category":"method","location":"index.html#Raycore.fast_intersect_triangle-Tuple{GeometryBasics.Point{3, Float32}, GeometryBasics.Vec{3, Float32}, GeometryBasics.Point{3, Float32}, GeometryBasics.Point{3, Float32}, GeometryBasics.Point{3, Float32}, Float32, Float32}","page":"Home","text":"fast_intersect_triangle(ray_o, ray_d, v0, v1, v2, t_min, closest_t) -> (hit, t, u, v)\n\nMöller-Trumbore ray-triangle intersection test. Matches HLSL reference implementation.\n\n\n\n\n\n","title":"Raycore.fast_intersect_triangle"},{"category":"method","location":"index.html#Raycore.fill_bvhnode2_kernel!-Tuple{Any}","page":"Home","text":"GPU kernel: Fill array with a value (workaround for OpenCL's fill! not supporting structs).\n\n\n\n\n\n","title":"Raycore.fill_bvhnode2_kernel!"},{"category":"method","location":"index.html#Raycore.find_span_for_node-Tuple{Int32, AbstractVector{UInt32}, Int32}","page":"Home","text":"Find the span of primitives covered by this internal node (Karras 2012).\n\n\n\n\n\n","title":"Raycore.find_span_for_node"},{"category":"method","location":"index.html#Raycore.find_split_in_span-Tuple{Int32, Int32, AbstractVector{UInt32}, Int32}","page":"Home","text":"Find the split position within a span (Karras 2012).\n\n\n\n\n\n","title":"Raycore.find_split_in_span"},{"category":"method","location":"index.html#Raycore.foreach_element-Union{Tuple{Textures}, Tuple{Data}, Tuple{F}, Tuple{F, StaticMultiTypeSet{Data, Textures}, Vararg{Any}}} where {F, Data<:Tuple, Textures}","page":"Home","text":"foreach_element(f, smv::StaticMultiTypeSet, args...)\n\nExecute function f for each element in the StaticMultiTypeSet, passing additional args. The function is called as f(element, linear_idx, args...) where element has a concrete type and linear_idx is the 1-based linear index across all type slots.\n\nUses compile-time unrolled loops for type stability. The function f must not capture variables - pass all data as args.\n\n\n\n\n\n","title":"Raycore.foreach_element"},{"category":"method","location":"index.html#Raycore.gather_children_bvh2-Tuple{UInt32, AbstractVector{BVHNode2}, Int32}","page":"Home","text":"Gather up to 4 children from a subtree of the binary BVH. Performs a BFS-like traversal to collect the 4 best children.\n\nReturns: (childindices, childaabbs, childcount, isleaf_flags)\n\n\n\n\n\n","title":"Raycore.gather_children_bvh2"},{"category":"method","location":"index.html#Raycore.get_isbits_ptr_type-Union{Tuple{T}, Tuple{KernelAbstractions.CPU, Type{T}}} where T","page":"Home","text":"Get the isbits pointer type for a given element type and backend.\n\n\n\n\n\n","title":"Raycore.get_isbits_ptr_type"},{"category":"method","location":"index.html#Raycore.get_node_aabb-Tuple{BVHNode2, Bool}","page":"Home","text":"Compute AABB from BVHNode2 for BLAS (BVH2IL format with triangle vertices in leaves).\n\n\n\n\n\n","title":"Raycore.get_node_aabb"},{"category":"method","location":"index.html#Raycore.get_node_aabb4-Tuple{BVHNode4}","page":"Home","text":"Get the node's total AABB (union of all valid children).\n\n\n\n\n\n","title":"Raycore.get_node_aabb4"},{"category":"method","location":"index.html#Raycore.get_tlas_node_aabb-Tuple{BVHNode2, Bool}","page":"Home","text":"Compute AABB from BVHNode2 for TLAS (AABBs stored directly in leaves).\n\n\n\n\n\n","title":"Raycore.get_tlas_node_aabb"},{"category":"method","location":"index.html#Raycore.intersect_all_children4-Tuple{BVHNode4, GeometryBasics.Vec{3, Float32}, GeometryBasics.Point{3, Float32}, Float32, Float32}","page":"Home","text":"intersect_all_children4(node, ray_inv_d, ray_o, t_min, t_max) -> sorted hits\n\nTest ray against all 4 children AABBs and return sorted by distance. Returns up to 4 (childidx, tentry) pairs, sorted near-to-far.\n\n\n\n\n\n","title":"Raycore.intersect_all_children4"},{"category":"method","location":"index.html#Raycore.intersect_internal_node-Tuple{BVHNode2, GeometryBasics.Vec{3, Float32}, GeometryBasics.Point{3, Float32}, Float32, Float32}","page":"Home","text":"intersect_internal_node(node, ray_inv_d, ray_o, t_min, t_max) -> (near_child, far_child)\n\nTest ray against internal node's two children AABBs. Returns ordered children indices (near first, far second). INVALID_NODE if child is not intersected. Matches HLSL IntersectInternalNode.\n\n\n\n\n\n","title":"Raycore.intersect_internal_node"},{"category":"method","location":"index.html#Raycore.intersect_leaf_node-Tuple{BVHNode2, GeometryBasics.Vec{3, Float32}, GeometryBasics.Point{3, Float32}, Float32, Float32}","page":"Home","text":"intersect_leaf_node(node, ray_d, ray_o, t_min, closest_t) -> (hit, t, u, v)\n\nTest ray against triangle stored in leaf node. Returns hit status and intersection parameters. Matches HLSL IntersectLeafNode.\n\n\n\n\n\n","title":"Raycore.intersect_leaf_node"},{"category":"method","location":"index.html#Raycore.intersect_p-Tuple{Bounds3, Raycore.AbstractRay, GeometryBasics.Vec{3, Float32}, GeometryBasics.Point3{UInt8}}","page":"Home","text":"dirisnegative: 1 – false, 2 – true\n\n\n\n\n\n","title":"Raycore.intersect_p"},{"category":"method","location":"index.html#Raycore.iota_kernel!-Tuple{Any}","page":"Home","text":"GPU kernel: Fill array with sequential indices [1, 2, 3, ..., n].\n\n\n\n\n\n","title":"Raycore.iota_kernel!"},{"category":"method","location":"index.html#Raycore.is_interior-Tuple{BVHNode2}","page":"Home","text":"Check if a node is an interior node.\n\n\n\n\n\n","title":"Raycore.is_interior"},{"category":"method","location":"index.html#Raycore.is_leaf-Tuple{BVHNode2}","page":"Home","text":"Check if a node is a leaf node.\n\n\n\n\n\n","title":"Raycore.is_leaf"},{"category":"method","location":"index.html#Raycore.leaf_index-Tuple{Integer, Int32}","page":"Home","text":"Compute leaf node index from primitive index.\n\n\n\n\n\n","title":"Raycore.leaf_index"},{"category":"method","location":"index.html#Raycore.maximum_extent-Tuple{Bounds3}","page":"Home","text":"Return index of the longest axis. Useful for deciding which axis to subdivide, when building ray-tracing acceleration structures.\n\n1 - x, 2 - y, 3 - z.\n\n\n\n\n\n","title":"Raycore.maximum_extent"},{"category":"method","location":"index.html#Raycore.morton_code_30bit-Tuple{GeometryBasics.Point{3, Float32}}","page":"Home","text":"Calculate 30-bit Morton code from normalized 3D point [0,1]³. Interleaves x,y,z bits to create space-filling Z-curve ordering.\n\n\n\n\n\n","title":"Raycore.morton_code_30bit"},{"category":"method","location":"index.html#Raycore.offset-Tuple{Bounds3, GeometryBasics.Point{3, Float32}}","page":"Home","text":"Get offset of a point from the minimum point of the bounds.\n\n\n\n\n\n","title":"Raycore.offset"},{"category":"method","location":"index.html#Raycore.rebuild_bvh!-Tuple{TLAS}","page":"Home","text":"Internal: Compact deleted instances and rebuild TLAS BVH.\n\n\n\n\n\n","title":"Raycore.rebuild_bvh!"},{"category":"method","location":"index.html#Raycore.rebuild_static_tlas!-Tuple{TLAS}","page":"Home","text":"rebuild_static_tlas!(tlas::TLAS)\n\nBuild a fresh StaticTLAS from the current tlas.nodes / tlas.instances / flat-BLAS arrays and store it on tlas.static_tlas. Called by sync! — not a public API; consumers read tlas.static_tlas or Adapt.adapt(backend, tlas).\n\n\n\n\n\n","title":"Raycore.rebuild_static_tlas!"},{"category":"method","location":"index.html#Raycore.refit_aabbs_kernel!-Tuple{Any}","page":"Home","text":"Parallel bottom-up AABB refit using atomic counters.\n\nEach thread starts at a leaf and walks up the tree. Uses atomic operations to ensure each internal node is updated exactly once after both children are ready. Based on RadeonRays Refit kernel.\n\n\n\n\n\n","title":"Raycore.refit_aabbs_kernel!"},{"category":"method","location":"index.html#Raycore.refit_tlas!-Tuple{TLAS}","page":"Home","text":"refit_tlas!(tlas::TLAS)\n\nRefit the TLAS after instance transforms have been updated. Updates leaf AABBs from instance transforms and propagates changes up the tree.\n\nThis is much faster than rebuilding the TLAS from scratch when only transforms change. Operates directly on the backend arrays stored in the TLAS.\n\n\n\n\n\n","title":"Raycore.refit_tlas!"},{"category":"method","location":"index.html#Raycore.refit_tlas_aabbs_kernel!-Tuple{Any}","page":"Home","text":"Parallel bottom-up AABB refit for TLAS using atomic counters. Uses gettlasnode_aabb which treats leaves as storing AABBs directly (not triangle vertices).\n\n\n\n\n\n","title":"Raycore.refit_tlas_aabbs_kernel!"},{"category":"method","location":"index.html#Raycore.safe_invdir-Tuple{GeometryBasics.Vec{3, Float32}}","page":"Home","text":"safe_invdir(d::Vec3f) -> Vec3f\n\nSafe ray direction inversion that avoids division by zero. Clamps near-zero components to ±1e-5. Matches HLSL reference implementation.\n\n\n\n\n\n","title":"Raycore.safe_invdir"},{"category":"method","location":"index.html#Raycore.set_parent_pointers_kernel!-Tuple{Any}","page":"Home","text":"GPU kernel: Parallel parent pointer assignment.\n\n\n\n\n\n","title":"Raycore.set_parent_pointers_kernel!"},{"category":"method","location":"index.html#Raycore.tlas_node_aabb-Tuple{BVHNode2}","page":"Home","text":"Get the AABB of a TLAS node (internal: union of children, leaf: stored AABB).\n\n\n\n\n\n","title":"Raycore.tlas_node_aabb"},{"category":"method","location":"index.html#Raycore.to_isbits_blas-Tuple{Any, BLAS, Vector{Raycore.BLASArrays}}","page":"Home","text":"Convert a BLAS with backend arrays to an isbits BLAS with device pointers.\n\nAppends a BLASArrays(nodes, primitives) to blas_storage so the backing buffers outlive every isbits pointer that references them.\n\nNote: The isbits BLAS is only used by management kernels that read root_aabb (inline data). For traversal, StaticTLAS uses flat arrays with offset-based indexing instead (see BLASDescriptor).\n\n\n\n\n\n","title":"Raycore.to_isbits_blas"},{"category":"method","location":"index.html#Raycore.update_instance_transform!-Tuple{TLAS, Integer, StaticArraysCore.SMatrix{4, 3, Float32, 12}}","page":"Home","text":"update_instance_transform!(tlas::TLAS, instance_idx::Integer, transform)\n\nUpdate the transform of a single instance. Call refit_tlas! after updating transforms.\n\nArguments\n\ntlas: The TLAS to update\ninstance_idx: 1-based index of the instance to update\ntransform: New local-to-world transform — Mat4f or canonical Vulkan row-major 3×4 (Mat3x4f)\n\n\n\n\n\n","title":"Raycore.update_instance_transform!"}]
}
